I18N.register("ro", {
  q: {
    "TPR1_01": ["Ce urmează? ◇, ◇◇, ◇◇◇, ◇◇◇◇, ?", "Numără romburii la fiecare pas.", ["◇◇◇◇◇", "◇◇◇", "◇◇◇◇", "◇◇"], "La fiecare pas se adaugă un romb: 1, 2, 3, 4, deci urmează 5 romburi."],
    "TPR1_02": ["Ce urmează? A, B, C, D, E, ?", "Gândește-te la ordinea literelor din alfabet.", ["F", "G", "D", "A"], "Sunt litere consecutive din alfabet, deci următoarea literă este F."],
    "TPR1_03": ["Ce urmează? 1, 2, 3, 4, 5, ?", "Fiecare număr crește cu același pas.", ["6", "7", "5", "8"], "Fiecare număr crește cu 1, deci după 5 urmează 6."],
    "TPR1_04": ["Ce urmează? 2, 4, 6, 8, ?", "Uită-te la diferența dintre numerele consecutive.", ["10", "12", "9", "11"], "Șirul merge din 2s. După 8, următorul număr par este 10."],
    "TPR1_05": ["Ce urmează? A, B, A, B, A, ?", "Observă tiparul care alternează.", ["B", "A", "C", "D"], "Tiparul alternează A, B încontinuu, deci după A urmează B."],
    "TPR1_06": ["Ce urmează? □, □□, □□□, ?", "Numără pătratele la fiecare pas.", ["□□□□", "□□", "□□□□□", "□□□"], "La fiecare pas se adaugă un pătrat: 1, 2, 3, deci urmează 4 pătrate."],
    "TPR1_07": ["Ce urmează? Z, Y, X, W, ?", "Alfabetul merge invers.", ["V", "U", "X", "T"], "Literele merg invers în alfabet: Z, Y, X, W, V."],
    "TPR1_08": ["Ce urmează? 10, 20, 30, 40, ?", "Fiecare număr crește cu același pas.", ["50", "45", "60", "55"], "Șirul merge din 10s. După 40, următorul termen este 50."],
    "TPR1_09": ["Ce urmează? 3, 6, 9, 12, ?", "Fiecare număr crește cu același pas.", ["15", "14", "18", "13"], "Șirul merge din 3s. După 12, următorul multiplu de 3 este 15."],
    "TPR1_10": ["Completează grila: 1, 3, 5 / 7, 9, 11 / 13, 15, ?", "Listează numerele impare în ordine, rând cu rând.", ["17", "16", "19", "18"], "Grila listează numere impare consecutive: 1, 3, 5, 7, …, 15, 17."],
    "TPR1_11": ["Ce urmează? ★, ★★, ★★★, ★★★★, ?", "Numără stelele la fiecare pas.", ["★★★★★", "★★★★", "★★★", "★★★★★★"], "La fiecare pas se adaugă o stea: 1, 2, 3, 4, deci urmează 5 stele."],
    "TPR1_12": ["Ce urmează? 6, 12, 18, 24, ?", "Fiecare număr este multiplu al cui?", ["30", "28", "36", "32"], "Șirul merge din 6s. După 24, următorul multiplu de 6 este 30."],
    "TPR1_13": ["Ce urmează? M, N, O, P, ?", "Sunt litere consecutive din alfabet.", ["Q", "R", "N", "S"], "Literele continuă în ordine în alfabet: M, N, O, P, Q."],
    "TPR1_14": ["Ce urmează? 1, 1, 1, 1, ?", "Se schimbă vreodată valoarea?", ["1", "2", "0", "3"], "Fiecare termen este 1 — tiparul e constant, deci următoarea valoare este 1."],
    "TPR1_15": ["Ce urmează? ♥, ♦, ♥, ♦, ♥, ?", "Două simboluri se alternează.", ["♦", "♥", "♣", "♠"], "Tiparul alternează heart, diamond. După heart urmează diamond."],
    "TPR1_16": ["Ce urmează? 8, 16, 24, 32, ?", "Uită-te la diferența dintre numerele consecutive.", ["40", "36", "48", "38"], "Șirul merge din 8s. După 32, următorul multiplu de 8 este 40."],
    "TPR1_17": ["Ce urmează? ♠, ♠♠, ♠♠♠, ?", "Numără simbolurile de treflă la fiecare pas.", ["♠♠♠♠", "♠♠", "♠♠♠", "♠♠♠♠♠"], "La fiecare pas se adaugă o treflă: 1, 2, 3, deci urmează 4 trefle."],
    "TPR1_18": ["Ce urmează? 30, 27, 24, 21, ?", "Numerele scad cu o cantitate fixă.", ["18", "20", "15", "19"], "Fiecare număr scade cu 3. După 21, următoarea valoare este 18."],
    "TPR1_19": ["Ce urmează? 7, 14, 21, 28, ?", "Fiecare număr este a multiple of a single digit.", ["35", "36", "32", "42"], "Șirul merge din 7s. După 28, următorul multiplu de 7 este 35."],
    "TPR1_20": ["Completează grila: 2, 4, 6 / 8, 10, 12 / 14, 16, ?", "Listează numerele pare rând cu rând.", ["18", "20", "17", "19"], "Grila listează numere pare consecutive: 2, 4, 6, 8, …, 16, 18."],
    "TPR2_01": ["Ce urmează? X, XY, XYX, XYXY, ?", "La fiecare pas se adaugă încă un caracter, alternând X și Y.", ["XYXYX", "XYXYY", "YXYXY", "XYXY"], "Tiparul crește prin adăugare alternativă: al 5-lea termen are 5 caractere: XYXYX."],
    "TPR2_02": ["Grilă: 3, 6, 9 / 5, 10, 15 / 8, 16, ?", "Uită-te cum se leagă fiecare rând de primul său număr.", ["24", "20", "18", "32"], "Fiecare rând înmulțește primul număr cu 1, 2, 3. Rândul 3: 8×1=8, 8×2=16, 8×3=24."],
    "TPR2_03": ["Ce urmează? AA, BB, CC, DD, ?", "Fiecare pereche folosește următoarea literă din alfabet.", ["EE", "FF", "DE", "AB"], "Fiecare termen este o literă consecutivă dublată: A, B, C, D, E → EE."],
    "TPR2_04": ["Ce urmează? 1, 3, 5, 7, 9, ?", "Sunt numere impare.", ["11", "10", "13", "12"], "Șirul listează numere impare consecutive. După 9, următorul număr impar este 11."],
    "TPR2_05": ["Ce urmează? ○●, ○●○, ○●○●, ○●○●○, ?", "La fiecare pas se adaugă încă o formă, alternând ○ și ●.", ["○●○●○●", "○●○●○○", "●○●○●○", "○●○●●○"], "Tiparul crește cu câte o formă la fiecare pas, alternând ○ și ●. Următorul are 6 forme: ○●○●○●."],
    "TPR2_06": ["Ce urmează? 2, 6, 10, 14, ?", "Găsește diferența constantă dintre termeni.", ["18", "16", "20", "15"], "Fiecare număr crește cu 4. După 14, următoarea valoare este 18."],
    "TPR2_07": ["Ce urmează? AB, CD, EF, GH, ?", "Fiecare pereche folosește următoarele două litere consecutive.", ["IJ", "JK", "HI", "KL"], "Perechile parcurg alfabetul câte două litere: AB, CD, EF, GH, IJ."],
    "TPR2_08": ["Grilă: 1, 3, 5 / 2, 4, 6 / 3, 5, ?", "Fiecare rând începe cu un număr mai mare și adaugă același pas.", ["7", "8", "6", "9"], "Fiecare rând listează trei numere care cresc cu 2. Rândul 3 începe la 3: 3, 5, 7."],
    "TPR2_09": ["Ce urmează? ○, ■, ○, ■, ○, ■, ?", "Două forme se repetă în ciclu.", ["○", "■", "△", "◇"], "Tiparul alternează ○ și ■. După ■ urmează ○."],
    "TPR2_10": ["Ce urmează? 20, 17, 14, 11, ?", "Numerele scad cu o cantitate fixă.", ["8", "9", "7", "10"], "Fiecare număr scade cu 3. După 11, următoarea valoare este 8."],
    "TPR2_11": ["Ce urmează? ABA, BCB, CDC, DED, ?", "Uită-te cum se deplasează cele trei litere din fiecare grup.", ["EFE", "FGF", "DEF", "EEE"], "Fiecare grup urmează tiparul: literă, litera următoare, aceeași primă literă — deplasat cu un pas la fiecare grup. După DED urmează EFE."],
    "TPR2_12": ["Grilă: 5, 10, 15 / 6, 12, 18 / 7, 14, ?", "Fiecare rând înmulțește primul număr cu 1, 2 și 3.", ["21", "20", "24", "28"], "Rândul 3: 7×1=7, 7×2=14, 7×3=21."],
    "TPR2_13": ["Ce urmează? 0, 2, 4, 6, 8, ?", "Sunt numere pare consecutive începând de la 0.", ["10", "12", "9", "11"], "Șirul listează even numbers: 0, 2, 4, 6, 8, 10."],
    "TPR2_14": ["Ce urmează? ○○, ■■, ○○, ■■, ?", "Perechile de forme alternează.", ["○○", "■■", "○■", "■○"], "Tiparul alternează pairs: ○○, ■■, ○○, ■■, ○○."],
    "TPR2_15": ["Ce urmează? 3, 7, 11, 15, 19, ?", "Găsește diferența comună dintre termeni.", ["23", "22", "21", "24"], "Fiecare număr crește cu 4. După 19, următoarea valoare este 23."],
    "TPR2_16": ["Grilă: 1, 2, 3 / 2, 4, 6 / 3, 6, ?", "Compară fiecare rând cu rândul de deasupra.", ["9", "8", "10", "12"], "Rândul n înmulțește 1, 2, 3 cu n. Rândul 3: 3×1=3, 3×2=6, 3×3=9."],
    "TPR2_17": ["Ce urmează? XY, WX, VW, UV, ?", "Fiecare pereche se deplasează cu o literă înapoi în alfabet.", ["TU", "ST", "RS", "SU"], "Fiecare pereche coboară o literă: XY → WX → VW → UV → TU."],
    "TPR2_18": ["Ce urmează? 40, 36, 32, 28, ?", "Numerele scad cu o constantă.", ["24", "25", "22", "20"], "Fiecare număr scade cu 4. După 28, următoarea valoare este 24."],
    "TPR2_19": ["Ce urmează? ○, ○○, ■, ■■, ○, ?", "O singură formă e urmată de dublul ei, apoi următoarea formă.", ["○○", "■", "○", "■■"], "Ciclul este: ○ simplu, ○○ dublu, ■ simplu, ■■ dublu, apoi se repetă. După ○ urmează ○○."],
    "TPR2_20": ["Grilă: 10, 20, 30 / 11, 22, 33 / 12, 24, ?", "Fiecare rând înmulțește primul număr cu 1, 2 și 3.", ["36", "34", "38", "48"], "Rândul 3: 12×1=12, 12×2=24, 12×3=36."],
    "TPR3_01": ["Ce urmează? 2, 3, 5, 8, 12, ?", "Uită-te la diferențele dintre termeni consecutivi — cresc cu 1.", ["17", "15", "16", "18"], "Diferențele sunt 1, 2, 3, 4, deci următoarea diferență este 5: 12 + 5 = 17."],
    "TPR3_02": ["Grilă: 3, 5, 15 / 4, 6, 24 / 7, 3, ?", "Cum se leagă primele două coloane de a treia?", ["21", "10", "24", "30"], "Coloana 1 × coloana 2 = coloana 3. Rândul 3: 7 × 3 = 21."],
    "TPR3_03": ["Ce urmează? 49, 36, 25, 16, 9, ?", "Fiecare termen este un pătrat perfect — care pătrate sunt acestea?", ["4", "1", "6", "3"], "Șirul este 7², 6², 5², 4², 3², deci următorul termen este 2² = 4."],
    "TPR3_04": ["Ce urmează? 20, 18, 15, 11, 6, ?", "Cantitatea scăzută crește cu 1 la fiecare pas.", ["0", "1", "2", "−1"], "Diferențele sunt −2, −3, −4, −5, deci următoarea diferență este −6: 6 − 6 = 0."],
    "TPR3_05": ["Grilă: 3, 9, 27 / 4, 16, 64 / 6, 36, ?", "Fiecare rând folosește puteri ale primului număr.", ["216", "180", "108", "72"], "Tiparul rândului este n¹, n², n³. Rândul 3: 6, 36, 216."],
    "TPR3_06": ["Ce urmează? 3, 5, 9, 15, 23, ?", "Calculează diferențele — formează propriul tipar.", ["33", "31", "35", "29"], "Diferențele sunt 2, 4, 6, 8, deci următoarea este 10: 23 + 10 = 33."],
    "TPR3_07": ["Grilă: 1, 5, 6 / 2, 8, 10 / 3, 11, ?", "Adună primele două coloane din fiecare rând.", ["14", "13", "15", "33"], "Coloana 1 + coloana 2 = coloana 3. Rândul 3: 3 + 11 = 14."],
    "TPR3_08": ["Ce urmează? 1, 6, 15, 28, 45, ?", "Uită-te la diferențe, apoi la diferențele acelor diferențe.", ["66", "60", "56", "72"], "Diferențele sunt 5, 9, 13, 17 (cresc cu 4). Următoarea diferență este 21: 45 + 21 = 66."],
    "TPR3_09": ["Ce urmează? 100, 95, 85, 70, 50, ?", "Cu cât se scade la fiecare pas? Această mărime crește.", ["25", "30", "20", "35"], "Diferențele sunt −5, −10, −15, −20, deci următorul termen este −25: 50 − 25 = 25."],
    "TPR3_10": ["Grilă: 3, 4, 12 / 5, 6, 30 / 7, 8, ?", "Cum se leagă coloana 3 de coloanele 1 și 2?", ["56", "15", "48", "60"], "Coloana 1 × coloana 2 = coloana 3. Rândul 3: 7 × 8 = 56."],
    "TPR3_11": ["Ce urmează? 3, 8, 15, 24, 35, ?", "Încearcă să exprimi fiecare termen ca n² minus something.", ["48", "44", "50", "42"], "Fiecare termen este n² − 1: 2²−1=3, 3²−1=8, 4²−1=15, 5²−1=24, 6²−1=35, 7²−1=48."],
    "TPR3_12": ["Grilă: 2, 10, 5 / 3, 18, 6 / 4, 28, ?", "Cum se leagă coloana 3 de celelalte coloane?", ["7", "8", "12", "32"], "Coloana 2 ÷ coloana 1 = coloana 3. Rândul 3: 28 ÷ 4 = 7."],
    "TPR3_13": ["Ce urmează? 5, 6, 8, 11, 15, 20, ?", "Diferențele dintre termeni increase by 1 la fiecare pas.", ["26", "25", "27", "24"], "Diferențele sunt 1, 2, 3, 4, 5, deci următoarea diferență este 6: 20 + 6 = 26."],
    "TPR3_14": ["Ce urmează? 2, 5, 10, 17, 26, ?", "Încearcă formula n² + 1 pentru valori consecutive ale lui n.", ["37", "35", "38", "36"], "Fiecare termen este n² + 1: 1²+1=2, 2²+1=5, 3²+1=10, 4²+1=17, 5²+1=26, 6²+1=37."],
    "TPR3_15": ["Grilă: 2, 5, 7 / 3, 4, 7 / 8, 3, ?", "Adună primele două coloane din fiecare rând.", ["11", "24", "5", "10"], "Coloana 1 + coloana 2 = coloana 3. Rândul 3: 8 + 3 = 11."],
    "TPR3_16": ["Grilă: 6, 2, 3 / 15, 3, 5 / 24, 4, ?", "Împarte coloana 1 la coloana 2.", ["6", "8", "7", "28"], "Coloana 1 ÷ coloana 2 = coloana 3. Rândul 3: 24 ÷ 4 = 6."],
    "TPR3_17": ["Ce urmează? 2, 8, 32, 128, ?", "Fiecare termen se înmulțește cu același număr.", ["512", "256", "384", "640"], "Fiecare termen este înmulțit cu 4. După 128, următorul termen este 128 × 4 = 512."],
    "TPR3_18": ["Ce urmează? 10, 12, 16, 22, 30, ?", "Vezi cum se schimbă intervalul dintre termeni.", ["40", "38", "42", "36"], "Diferențele sunt 2, 4, 6, 8, deci următoarea este 10: 30 + 10 = 40."],
    "TPR3_19": ["Ce urmează? 4, 7, 12, 19, 28, ?", "Diferențele dintre termeni grow by 2 la fiecare pas.", ["39", "37", "41", "35"], "Diferențele sunt 3, 5, 7, 9, deci următoarea diferență este 11: 28 + 11 = 39."],
    "TPR3_20": ["Grilă: 4, 2, 8 / 9, 3, 27 / 16, 4, ?", "Coloana 1 este un pătrat perfect. Care sunt valorile cubului?", ["64", "48", "32", "20"], "Coloana 1 = n², coloana 2 = n, coloana 3 = n³. Rândul 3: 4² = 16, 4, 4³ = 64."],
    "TPR4_01": ["Ce urmează? 1, 16, 81, 256, ?", "Fiecare termen este o putere a patra.", ["625", "512", "500", "1024"], "Șirul este 1⁴, 2⁴, 3⁴, 4⁴, deci următorul termen este 5⁴ = 625."],
    "TPR4_02": ["Grilă: 5, 25, 125 / 6, 36, 216 / 7, 49, ?", "Fiecare rând arată n, n², n³.", ["343", "294", "350", "336"], "Rândul 3: 7¹ = 7, 7² = 49, 7³ = 343."],
    "TPR4_03": ["Ce urmează? 2, 8, 26, 80, 242, ?", "Încearcă să exprimi fiecare termen ca a power of 3 minus 1.", ["728", "486", "720", "500"], "Fiecare termen este 3ⁿ − 1: 3¹−1=2, 3²−1=8, 3³−1=26, 3⁴−1=80, 3⁵−1=242, 3⁶−1=728."],
    "TPR4_04": ["Ce urmează? 1, 4, 13, 40, 121, ?", "Fiecare termen se triplează și apoi se mărește cu 1.", ["364", "242", "360", "400"], "Fiecare termen = previous × 3 + 1: 1→4, 4→13, 13→40, 40→121, 121→364."],
    "TPR4_05": ["Ce urmează? 2, 3, 5, 8, 13, ?", "Uită-te la diferențe — urmează un tipar cunoscut.", ["21", "18", "20", "16"], "Diferențele sunt 1, 2, 3, 5, 8 — fiecare diferență e suma celor două dinaintea ei. Următoarea diferență e 8, deci 13 + 8 = 21."],
    "TPR4_06": ["Ce urmează? 1, 4, 10, 20, 35, ?", "Uită-te la diferențele de ordinul al doilea — cresc cu 1.", ["56", "50", "48", "55"], "Diferențe de ordinul I: 3, 6, 10, 15. Diferențe de ordinul II: 3, 4, 5 → next is 6. Următoarea diferență de ordinul I: 21. Răspuns: 35 + 21 = 56."],
    "TPR4_07": ["Ce urmează? 1, 3, 2, 6, 4, 12, 8, ?", "Împarte șirul în termeni pe poziții impare și pare.", ["24", "16", "10", "20"], "Poziții impare: 1, 2, 4, 8 (×2). Poziții pare: 3, 6, 12, 24 (×2). Următorul termen pe poziție pară este 24."],
    "TPR4_08": ["Grilă: 2, 3, 11 / 4, 5, 29 / 6, 7, ?", "Încearcă (coloana 1 + 1) × (coloana 2 + 1) și ajustează.", ["55", "42", "48", "53"], "Coloana 3 = (coloana 1 + 1) × (coloana 2 + 1) − 1. Rândul 3: 7 × 8 − 1 = 55."],
    "TPR4_09": ["Ce urmează? 256, 128, 64, 32, 16, ?", "Fiecare termen se înjumătățește.", ["8", "4", "12", "10"], "Fiecare termen se împarte la 2. După 16, următorul termen este 16 ÷ 2 = 8."],
    "TPR4_10": ["Grilă: 1, 2, 3, 6 / 2, 3, 5, 30 / 3, 4, 7, ?", "Cum se leagă ultima coloană de primele trei?", ["84", "14", "21", "72"], "Coloana 4 = coloana 1 × coloana 2 × coloana 3. Rândul 3: 3 × 4 × 7 = 84."],
    "TPR4_11": ["Ce urmează? 2, 6, 18, 54, ?", "Fiecare termen se înmulțește cu același număr.", ["162", "108", "144", "216"], "Fiecare termen este înmulțit cu 3. După 54, următorul termen este 54 × 3 = 162."],
    "TPR4_12": ["Ce urmează? 1, 5, 14, 30, 55, ?", "Diferențele dintre termeni are perfect squares.", ["91", "80", "85", "90"], "Diferențele sunt 4, 9, 16, 25 (which are 2², 3², 4², 5²). Următoarea diferență este 6² = 36: 55 + 36 = 91."],
    "TPR4_13": ["Ce urmează? 1000, 500, 250, 125, ?", "Fiecare termen se înjumătățește.", ["62.5", "60", "75", "100"], "Fiecare termen se împarte la 2. După 125, următorul termen este 125 ÷ 2 = 62.5."],
    "TPR4_14": ["Grilă: 10, 3, 7 / 20, 8, 12 / 30, 11, ?", "Cum se leagă coloanele aritmetic?", ["19", "20", "21", "41"], "Coloana 1 − coloana 2 = coloana 3. Rândul 3: 30 − 11 = 19."],
    "TPR4_15": ["Ce urmează? 4, 5, 9, 14, 23, 37, ?", "Fiecare termen este suma celor doi termeni anteriori.", ["60", "51", "56", "74"], "Ca la Fibonacci: fiecare termen = suma celor doi precedenți. 23 + 37 = 60."],
    "TPR4_16": ["Grilă: 2, 8, 3 / 3, 27, 8 / 4, 64, ?", "Coloana 2 este o putere a coloanei 1. Ce tipar urmează coloana 3?", ["15", "16", "12", "20"], "Coloana 2 = coloana 1³. Coloana 3 = coloana 1² − 1: 2²−1=3, 3²−1=8, 4²−1=15."],
    "TPR4_17": ["Ce urmează? 1, 5, 21, 85, ?", "Încearcă să înmulțești fiecare termen cu 4 și să aduni 1.", ["341", "256", "340", "345"], "Fiecare termen = previous × 4 + 1: 1→5, 5→21, 21→85, 85→341."],
    "TPR4_18": ["Ce urmează? 1, 2, 5, 12, 29, ?", "Fiecare termen folosește cei doi anteriori cu un multiplicator.", ["70", "58", "65", "72"], "Regula: a(n) = 2×a(n−1) + a(n−2). Verificare: 2×2+1=5, 2×5+2=12, 2×12+5=29, 2×29+12=70."],
    "TPR4_19": ["Grilă: 3, 2, 11 / 4, 3, 19 / 5, 4, ?", "Încearcă coloana 1 la pătrat plus coloana 2.", ["29", "20", "25", "30"], "Coloana 3 = coloana 1² + coloana 2. Rândul 3: 5² + 4 = 25 + 4 = 29."],
    "TPR4_20": ["Grilă: 4, 3, 13 / 5, 2, 23 / 6, 1, ?", "Încearcă coloana 1 la pătrat minus coloana 2.", ["35", "30", "36", "42"], "Coloana 3 = coloana 1² − coloana 2. Rândul 3: 6² − 1 = 36 − 1 = 35."],
    "TPR5_01": ["Ce urmează în șirul numerelor prime? 23, 29, 31, 37, 41, ?", "Listează numerele prime după 41.", ["43", "42", "45", "47"], "Șirul listează numere prime consecutive. După 41, următorul număr prim este 43."],
    "TPR5_02": ["Ce urmează? 2, 1, 3, 4, 7, 11, 18, ?", "Fiecare termen este suma celor doi termeni anteriori.", ["29", "25", "27", "36"], "Șir de tip Lucas: fiecare termen = suma celor doi dinaintea lui. 11 + 18 = 29."],
    "TPR5_03": ["Grilă: 2, 8, 32 / 3, 27, 243 / 5, 125, ?", "Fiecare coloană folosește o putere impară a primului număr.", ["3125", "625", "1250", "1500"], "Tiparul rândului este n¹, n³, n⁵. Rândul 3: 5¹=5, 5³=125, 5⁵=3125."],
    "TPR5_04": ["Ce urmează? 4, 6, 10, 14, 22, 26, ?", "Fiecare termen este de două ori un număr prim. Care prime?", ["34", "30", "32", "38"], "Fiecare termen este 2 × a consecutive prime: 2×2=4, 2×3=6, 2×5=10, 2×7=14, 2×11=22, 2×13=26, 2×17=34."],
    "TPR5_05": ["Ce urmează? 0, 0, 1, 1, 2, 4, 7, 13, ?", "Fiecare termen este suma celor trei termeni anteriori.", ["24", "20", "26", "19"], "Este șirul Tribonacci: fiecare termen = suma celor trei dinaintea lui. 4 + 7 + 13 = 24."],
    "TPR5_06": ["Ce urmează? 2, 12, 36, 80, 150, ?", "Încearcă să exprimi fiecare termen ca n²(n + 1).", ["252", "210", "240", "260"], "Fiecare termen este n²(n+1): 1²×2=2, 2²×3=12, 3²×4=36, 4²×5=80, 5²×6=150, 6²×7=252."],
    "TPR5_07": ["Grilă: 1, 2, 5 / 2, 3, 13 / 4, 5, ?", "Încearcă pătratele primelor două coloane adunate.", ["41", "20", "45", "36"], "Coloana 3 = coloana 1² + coloana 2². Rândul 3: 4² + 5² = 16 + 25 = 41."],
    "TPR5_08": ["Ce urmează? 2, 8, 18, 32, 50, ?", "Încearcă să exprimi fiecare termen ca 2n² for consecutive values of n.", ["72", "60", "68", "80"], "Fiecare termen este 2n²: 2(1²)=2, 2(2²)=8, 2(3²)=18, 2(4²)=32, 2(5²)=50, 2(6²)=72."],
    "TPR5_09": ["Ce urmează? 2, 4, 16, 256, ?", "Fiecare termen este pătratul termenului anterior.", ["65536", "512", "1024", "4096"], "Fiecare termen = previous². 2²=4, 4²=16, 16²=256, 256²=65536."],
    "TPR5_10": ["Ce urmează? 47, 43, 41, 37, 31, 29, ?", "Sunt numere prime in descending order.", ["23", "27", "25", "19"], "Șirul listează numere prime consecutive în ordine descrescătoare. După 29, următorul număr prim mai mic este 23."],
    "TPR5_11": ["Grilă: 2, 3, 7 / 4, 5, 21 / 6, 7, ?", "Înmulțește primele două coloane și ajustează cu 1.", ["43", "42", "44", "40"], "Coloana 3 = coloana 1 × coloana 2 + 1. Rândul 3: 6 × 7 + 1 = 43."],
    "TPR5_12": ["Ce urmează? 1, 5, 12, 22, 35, ?", "Acestea sunt pentagonal numbers: n(3n − 1)/2.", ["51", "48", "50", "55"], "Numere pentagonale: n(3n−1)/2. Pentru n=6: 6×17/2 = 51."],
    "TPR5_13": ["Ce urmează? 2, 6, 30, 210, ?", "Fiecare termen se înmulțește cu următorul număr prim.", ["2310", "1470", "1260", "1890"], "2×3=6, 6×5=30, 30×7=210, 210×11=2310. La fiecare pas înmulțești cu următorul număr prim."],
    "TPR5_14": ["Grilă: 4, 16, 64 / 6, 36, 216 / 8, 64, ?", "Fiecare rând arată puteri ale primului număr.", ["512", "256", "480", "128"], "Tiparul rândului este n¹, n², n³. Rândul 3: 8, 64, 512."],
    "TPR5_15": ["Ce urmează? 1, 3, 11, 43, ?", "Fiecare termen se înmulțește cu 4 și apoi se micșorează cu 1.", ["171", "170", "172", "160"], "Fiecare termen = previous × 4 − 1: 1→3, 3→11, 11→43, 43→171."],
    "TPR5_16": ["Ce urmează? 59, 53, 47, 43, 41, 37, ?", "Acestea sunt numere prime listate în ordine descrescătoare.", ["31", "33", "29", "35"], "Șirul listează consecutive primes in reverse order. După 37, următorul număr prim mai mic este 31."],
    "TPR5_17": ["Ce urmează? 27, 125, 343, 729, ?", "Fiecare termen este un cub — ale căror numere?", ["1331", "1000", "1200", "1500"], "Acestea sunt cuburi ale numerelor impare consecutive: 3³=27, 5³=125, 7³=343, 9³=729, 11³=1331."],
    "TPR5_18": ["Grilă: 3, 2, 18 / 4, 3, 48 / 5, 4, ?", "Încearcă coloana 1 la pătrat înmulțită cu coloana 2.", ["100", "80", "60", "125"], "Coloana 3 = coloana 1² × coloana 2. Rândul 3: 5² × 4 = 25 × 4 = 100."],
    "TPR5_19": ["Ce urmează? 2, 3, 6, 7, 14, 15, ?", "Șirul alternează între două operații.", ["30", "16", "28", "22"], "Tiparul alternează +1 și ×2: 2+1=3, 3×2=6, 6+1=7, 7×2=14, 14+1=15, 15×2=30."],
    "TPR5_20": ["Ce urmează? 1, 9, 36, 100, 225, ?", "Fiecare termen este un pătrat perfect. La ce numere sunt ridicate?", ["441", "400", "484", "500"], "Acestea sunt pătrate ale sumelor cumulative: (1)²=1, (1+2)²=9, (1+2+3)²=36, (1+2+3+4)²=100, (1+2+3+4+5)²=225, (1+2+3+4+5+6)²=441."],
    "TNR1_01": ["Ce urmează în șirul: 7, 8, 9, 10, 11, ?", "Uită-te la diferența dintre fiecare pereche de termeni consecutivi.", ["12", "13", "10", "14"], "Fiecare termen crește cu 1. Următorul termen este 11 + 1 = 12."],
    "TNR1_02": ["Ce urmează în șirul: 3, 5, 7, 9, 11, ?", "Scade fiecare termen din următorul.", ["13", "12", "14", "15"], "Fiecare termen crește cu 2. Următorul termen este 11 + 2 = 13."],
    "TNR1_03": ["Ce urmează în șirul: 10, 13, 16, 19, 22, ?", "Găsește diferența constantă dintre termenii consecutivi.", ["25", "24", "26", "23"], "Fiecare termen crește cu 3. Următorul termen este 22 + 3 = 25."],
    "TNR1_04": ["Ce urmează în șirul: 1, 5, 9, 13, 17, ?", "Cu cât crește fiecare termen față de cel anterior?", ["21", "20", "22", "19"], "Fiecare termen crește cu 4. Următorul termen este 17 + 4 = 21."],
    "TNR1_05": ["Ce urmează în șirul: 2, 7, 12, 17, 22, ?", "Calculează pasul dintre termeni consecutivi.", ["27", "25", "28", "26"], "Fiecare termen crește cu 5. Următorul termen este 22 + 5 = 27."],
    "TNR1_06": ["Ce urmează în șirul: 4, 10, 16, 22, 28, ?", "Ce se adaugă de fiecare dată?", ["34", "32", "36", "30"], "Fiecare termen crește cu 6. Următorul termen este 28 + 6 = 34."],
    "TNR1_07": ["Ce urmează în șirul: 3, 10, 17, 24, 31, ?", "Găsește constanta adăugată la fiecare termen.", ["38", "35", "39", "37"], "Fiecare termen crește cu 7. Următorul termen este 31 + 7 = 38."],
    "TNR1_08": ["Ce urmează în șirul: 5, 13, 21, 29, 37, ?", "Scade primul termen din al doilea ca să găsești mărimea pasului.", ["45", "44", "46", "43"], "Fiecare termen crește cu 8. Următorul termen este 37 + 8 = 45."],
    "TNR1_09": ["Ce urmează în șirul: 2, 11, 20, 29, 38, ?", "Ce număr se adaugă la fiecare pas?", ["47", "45", "48", "46"], "Fiecare termen crește cu 9. Următorul termen este 38 + 9 = 47."],
    "TNR1_10": ["Ce urmează în șirul: 6, 16, 26, 36, 46, ?", "Uită-te la intervalul dintre oricare doi termeni consecutivi.", ["56", "54", "58", "52"], "Fiecare termen crește cu 10. Următorul termen este 46 + 10 = 56."],
    "TNR1_11": ["Ce urmează în șirul: 20, 19, 18, 17, 16, ?", "Șirul scade. Cu cât la fiecare pas?", ["15", "14", "17", "13"], "Fiecare termen scade cu 1. Următorul termen este 16 − 1 = 15."],
    "TNR1_12": ["Ce urmează în șirul: 30, 28, 26, 24, 22, ?", "Scade fiecare termen din cel dinaintea lui.", ["20", "21", "18", "19"], "Fiecare termen scade cu 2. Următorul termen este 22 − 2 = 20."],
    "TNR1_13": ["Ce urmează în șirul: 40, 37, 34, 31, 28, ?", "Șirul scade. Găsește pasul constant.", ["25", "26", "24", "27"], "Fiecare termen scade cu 3. Următorul termen este 28 − 3 = 25."],
    "TNR1_14": ["Ce urmează în șirul: 50, 46, 42, 38, 34, ?", "Cu cât se scade de fiecare dată?", ["30", "32", "28", "31"], "Fiecare termen scade cu 4. Următorul termen este 34 − 4 = 30."],
    "TNR1_15": ["Ce urmează în șirul: 60, 55, 50, 45, 40, ?", "Găsește măsura scăzută între termenii consecutivi.", ["35", "30", "38", "33"], "Fiecare termen scade cu 5. Următorul termen este 40 − 5 = 35."],
    "TNR1_16": ["Ce urmează în șirul: 5, 16, 27, 38, 49, ?", "Calculează diferența dintre primii doi termeni și verifică dacă rămâne aceeași.", ["60", "58", "61", "55"], "Fiecare termen crește cu 11. Următorul termen este 49 + 11 = 60."],
    "TNR1_17": ["Ce urmează în șirul: 3, 15, 27, 39, 51, ?", "Care este constanta adăugată la fiecare pas?", ["63", "60", "64", "62"], "Fiecare termen crește cu 12. Următorul termen este 51 + 12 = 63."],
    "TNR1_18": ["Ce urmează în șirul: 10, 25, 40, 55, 70, ?", "Găsește pasul fix adăugat între termeni.", ["85", "80", "90", "75"], "Fiecare termen crește cu 15. Următorul termen este 70 + 15 = 85."],
    "TNR1_19": ["Ce urmează în șirul: 5, 25, 45, 65, 85, ?", "Calculează pasul de la un termen la următorul.", ["105", "100", "110", "95"], "Fiecare termen crește cu 20. Următorul termen este 85 + 20 = 105."],
    "TNR1_20": ["Ce urmează în șirul: 42, 36, 30, 24, 18, ?", "Șirul scade. Ce se scade de fiecare dată?", ["12", "14", "10", "16"], "Fiecare termen scade cu 6. Următorul termen este 18 − 6 = 12."],
    "TNR2_01": ["Ce urmează în șirul: 5, 10, 20, 40, 80, ?", "Încearcă să împarți fiecare termen la cel anterior.", ["160", "120", "140", "100"], "Fiecare termen se înmulțește cu 2. Următorul termen este 80 × 2 = 160."],
    "TNR2_02": ["Ce urmează în șirul: 2, 6, 18, 54, 162, ?", "Care este raportul dintre termenii consecutivi?", ["486", "324", "480", "648"], "Fiecare termen se înmulțește cu 3. Următorul termen este 162 × 3 = 486."],
    "TNR2_03": ["Ce urmează în șirul: 1, 4, 16, 64, 256, ?", "Împarte al doilea termen la primul pentru a găsi multiplicatorul.", ["1024", "512", "768", "1280"], "Fiecare termen se înmulțește cu 4. Următorul termen este 256 × 4 = 1024."],
    "TNR2_04": ["Ce urmează în șirul: 2, 10, 50, 250, 1250, ?", "Uită-te la raportul dintre termenii consecutivi.", ["6250", "5000", "6000", "7500"], "Fiecare termen se înmulțește cu 5. Următorul termen este 1250 × 5 = 6250."],
    "TNR2_05": ["Ce urmează în șirul: 3, 30, 300, 3000, 30000, ?", "Fiecare termen câștigă un zero în plus. Ce înmulțitor corespunde?", ["300000", "60000", "200000", "330000"], "Fiecare termen se înmulțește cu 10. Următorul termen este 30000 × 10 = 300000."],
    "TNR2_06": ["Ce urmează în șirul: 640, 320, 160, 80, 40, ?", "Șirul se înjumătățește. Ce operație se aplică la fiecare pas?", ["20", "10", "30", "25"], "Fiecare termen se împarte la 2. Următorul termen este 40 ÷ 2 = 20."],
    "TNR2_07": ["Ce urmează în șirul: 729, 243, 81, 27, 9, ?", "Încearcă să împarți fiecare termen la următorul.", ["3", "6", "1", "4"], "Fiecare termen se împarte la 3. Următorul termen este 9 ÷ 3 = 3."],
    "TNR2_08": ["Ce urmează în șirul: 192, 96, 48, 24, 12, ?", "Ce fracțiune din termenul anterior dă termenul curent?", ["6", "4", "8", "3"], "Fiecare termen se împarte la 2. Următorul termen este 12 ÷ 2 = 6."],
    "TNR2_09": ["Ce urmează în șirul: 3, 4, 7, 11, 18, ?", "Încearcă să aduni doi termeni consecutivi.", ["29", "25", "27", "30"], "Fiecare termen este suma celor doi termeni precedenți: 11 + 18 = 29."],
    "TNR2_10": ["Ce urmează în șirul: 2, 5, 7, 12, 19, ?", "Uită-te cum se leagă fiecare termen de cei doi dinaintea lui.", ["31", "26", "28", "33"], "Fiecare termen este suma celor doi termeni precedenți: 12 + 19 = 31."],
    "TNR2_11": ["Ce urmează în șirul: 4, 9, 19, 39, 79, ?", "Încearcă să dublezi un termen și apoi să ajustezi cu un număr mic pentru următorul.", ["159", "158", "160", "149"], "Fiecare termen respectă regula: previous × 2 + 1. Următorul termen este 79 × 2 + 1 = 159."],
    "TNR2_12": ["Ce urmează în șirul: 4, 12, 36, 108, 324, ?", "Împarte fiecare termen la cel anterior pentru a găsi un raport constant.", ["972", "648", "1296", "900"], "Fiecare termen se înmulțește cu 3. Următorul termen este 324 × 3 = 972."],
    "TNR2_13": ["Ce urmează în șirul: 7, 14, 28, 56, 112, ?", "Ce se întâmplă când împarți fiecare termen la cel dinaintea lui?", ["224", "168", "220", "228"], "Fiecare termen se înmulțește cu 2. Următorul termen este 112 × 2 = 224."],
    "TNR2_14": ["Ce urmează în șirul: 1, 3, 4, 7, 11, ?", "Verifică dacă fiecare termen e suma celor doi dinaintea lui.", ["18", "15", "16", "20"], "Fiecare termen este suma celor doi termeni precedenți: 7 + 11 = 18."],
    "TNR2_15": ["Ce urmează în șirul: 256, 128, 64, 32, 16, ?", "Acestea sunt all powers of 2. What divisor connects each pair?", ["8", "4", "12", "10"], "Fiecare termen se împarte la 2. Următorul termen este 16 ÷ 2 = 8."],
    "TNR2_16": ["Ce urmează în șirul: 1, 5, 25, 125, 625, ?", "Găsește multiplicatorul împărțind orice termen la cel anterior.", ["3125", "1250", "3000", "3750"], "Fiecare termen se înmulțește cu 5. Următorul termen este 625 × 5 = 3125."],
    "TNR2_17": ["Ce urmează în șirul: 3, 8, 18, 38, 78, ?", "Încearcă să dublezi termenul anterior și să aduni o constantă mică.", ["158", "156", "160", "148"], "Fiecare termen respectă regula: previous × 2 + 2. Următorul termen este 78 × 2 + 2 = 158."],
    "TNR2_18": ["Ce urmează în șirul: 1, 4, 5, 9, 14, ?", "Vezi dacă suma a doi termeni consecutivi dă următorul.", ["23", "19", "21", "25"], "Fiecare termen este suma celor doi termeni precedenți: 9 + 14 = 23."],
    "TNR2_19": ["Ce urmează în șirul: 2187, 729, 243, 81, 27, ?", "Fiecare termen este o fracțiune din cel anterior. Ce divizor se folosește?", ["9", "3", "18", "12"], "Fiecare termen se împarte la 3. Următorul termen este 27 ÷ 3 = 9."],
    "TNR2_20": ["Ce urmează în șirul: 2, 8, 32, 128, 512, ?", "Împarte termenii consecutivi pentru a găsi multiplicatorul constant.", ["2048", "1024", "2560", "1536"], "Fiecare termen se înmulțește cu 4. Următorul termen este 512 × 4 = 2048."],
    "TNR3_01": ["Ce urmează în șirul: 36, 49, 64, 81, 100, ?", "Încearcă rădăcina pătrată a fiecărui termen.", ["121", "110", "120", "125"], "Sunt consecutive perfect squares: 6²=36, 7²=49, 8²=64, 9²=81, 10²=100, 11²=121."],
    "TNR3_02": ["Ce urmează în șirul: 100, 121, 144, 169, 196, ?", "Fiecare termen este un pătrat perfect. Despre ce pătrate e vorba?", ["225", "220", "230", "216"], "Sunt consecutive perfect squares: 10²=100, 11²=121, 12²=144, 13²=169, 14²=196, 15²=225."],
    "TNR3_03": ["Ce urmează în șirul: 125, 216, 343, 512, 729, ?", "Încearcă rădăcina cubică a fiecărui termen.", ["1000", "900", "1024", "972"], "Sunt consecutive perfect cubes: 5³=125, 6³=216, 7³=343, 8³=512, 9³=729, 10³=1000."],
    "TNR3_04": ["Ce urmează în șirul: 343, 512, 729, 1000, 1331, ?", "Acestea sunt cubes of consecutive integers. Care integers?", ["1728", "1500", "1700", "2000"], "Sunt consecutive perfect cubes: 7³=343, 8³=512, 9³=729, 10³=1000, 11³=1331, 12³=1728."],
    "TNR3_05": ["Ce urmează în șirul: 10, 12, 16, 22, 30, ?", "Calculează diferențele dintre termeni. Aceste diferențe formează un tipar?", ["40", "38", "42", "36"], "Diferențele sunt 2, 4, 6, 8 — increasing by 2 la fiecare pas. Următoarea diferență este 10, so 30 + 10 = 40."],
    "TNR3_06": ["Ce urmează în șirul: 7, 10, 16, 25, 37, ?", "Găsește diferențele dintre termeni, apoi caută un tipar în aceste diferențe.", ["52", "49", "55", "46"], "Diferențele sunt 3, 6, 9, 12 — increasing by 3 la fiecare pas. Următoarea diferență este 15, so 37 + 15 = 52."],
    "TNR3_07": ["Ce urmează în șirul: 5, 6, 9, 14, 21, ?", "Diferențele dintre termeni are consecutive odd numbers.", ["30", "28", "32", "27"], "Diferențele sunt 1, 3, 5, 7 — consecutive odd numbers. Următoarea diferență este 9, so 21 + 9 = 30."],
    "TNR3_08": ["Ce urmează în șirul: 5, 7, 11, 13, 17, ?", "Gândește-te la numere care au exact doi divizori.", ["19", "18", "21", "20"], "Sunt numere prime consecutive începând de la 5. Următorul prim după 17 este 19."],
    "TNR3_09": ["Ce urmează în șirul: 11, 13, 17, 19, 23, ?", "Sunt aceste numere divizibile doar cu 1 și cu ele însele?", ["29", "27", "25", "31"], "Sunt numere prime consecutive începând de la 11. Următorul prim după 23 este 29."],
    "TNR3_10": ["Ce urmează în șirul: 4, 16, 36, 64, 100, ?", "Extrage rădăcina pătrată din fiecare termen. Ce au în comun aceste numere?", ["144", "128", "136", "148"], "Acestea sunt pătrate ale numerelor pare consecutive: 2²=4, 4²=16, 6²=36, 8²=64, 10²=100, 12²=144."],
    "TNR3_11": ["Ce urmează în șirul: 1, 9, 25, 49, 81, ?", "Extrage rădăcina pătrată din fiecare termen. Ce tip de numere sunt?", ["121", "100", "110", "125"], "Acestea sunt pătrate ale numerelor impare consecutive: 1²=1, 3²=9, 5²=25, 7²=49, 9²=81, 11²=121."],
    "TNR3_12": ["Ce urmează în șirul: 2, 5, 10, 17, 26, ?", "Scade 1 din fiecare termen. Rezultatele îți par familiare?", ["37", "35", "36", "39"], "Fiecare termen este egal cu n² + 1: 1²+1=2, 2²+1=5, 3²+1=10, 4²+1=17, 5²+1=26, 6²+1=37."],
    "TNR3_13": ["Ce urmează în șirul: 0, 3, 8, 15, 24, ?", "Adună 1 la fiecare termen. Ce șir cunoscut obții?", ["35", "33", "36", "30"], "Fiecare termen este egal cu n² − 1: 1²−1=0, 2²−1=3, 3²−1=8, 4²−1=15, 5²−1=24, 6²−1=35."],
    "TNR3_14": ["Ce urmează în șirul: 5, 9, 17, 29, 45, ?", "Calculează diferențele, apoi verifică dacă aceste diferențe cresc regulat.", ["65", "61", "69", "57"], "Diferențele sunt 4, 8, 12, 16 — increasing by 4 la fiecare pas. Următoarea diferență este 20, so 45 + 20 = 65."],
    "TNR3_15": ["Ce urmează în șirul: 2, 9, 28, 65, 126, ?", "Scade 1 din fiecare termen. Ce fel de numere rămân?", ["217", "215", "220", "210"], "Fiecare termen este egal cu n³ + 1: 1³+1=2, 2³+1=9, 3³+1=28, 4³+1=65, 5³+1=126, 6³+1=217."],
    "TNR3_16": ["Ce urmează în șirul: 3, 8, 15, 24, 35, ?", "Încearcă să exprimi fiecare termen ca a product of two numbers close together.", ["48", "46", "50", "44"], "Fiecare termen este egal cu n(n + 2): 1×3=3, 2×4=8, 3×5=15, 4×6=24, 5×7=35, 6×8=48."],
    "TNR3_17": ["Ce urmează în șirul: 1, 5, 11, 19, 29, ?", "Diferențele dintre termeni increase by a constant. Găsește that constant.", ["41", "39", "43", "37"], "Diferențele sunt 4, 6, 8, 10 — increasing by 2 la fiecare pas. Următoarea diferență este 12, so 29 + 12 = 41."],
    "TNR3_18": ["Ce urmează în șirul: 2, 8, 18, 32, 50, ?", "Încearcă să împarți fiecare termen la 2. Rezultatele îți par familiare?", ["72", "68", "74", "64"], "Fiecare termen este egal cu 2n²: 2(1²)=2, 2(2²)=8, 2(3²)=18, 2(4²)=32, 2(5²)=50, 2(6²)=72."],
    "TNR3_19": ["Ce urmează în șirul: 4, 7, 12, 19, 28, ?", "Scade 3 din fiecare termen. Ce șir recunoști?", ["39", "37", "41", "36"], "Fiecare termen este egal cu n² + 3: 1²+3=4, 2²+3=7, 3²+3=12, 4²+3=19, 5²+3=28, 6²+3=39."],
    "TNR3_20": ["Ce urmează în șirul: 4, 9, 19, 34, 54, ?", "Găsește diferențele, apoi diferențele acelor diferențe.", ["79", "74", "84", "69"], "Diferențele sunt 5, 10, 15, 20 — increasing by 5 la fiecare pas. Următoarea diferență este 25, so 54 + 25 = 79."],
    "TNR4_01": ["Ce urmează în șirul: 2, 3, 7, 25, 121, ?", "Scade 1 din fiecare termen și vezi dacă recunoști aceste numere.", ["721", "720", "625", "719"], "Fiecare termen este egal cu n! + 1: 1!+1=2, 2!+1=3, 3!+1=7, 4!+1=25, 5!+1=121, 6!+1=721."],
    "TNR4_02": ["Ce urmează în șirul: 0, 1, 5, 23, 119, ?", "Adună 1 la fiecare termen. Recunoști numerele rezultate?", ["719", "720", "600", "721"], "Fiecare termen este egal cu n! − 1: 1!−1=0, 2!−1=1, 3!−1=5, 4!−1=23, 5!−1=119, 6!−1=719."],
    "TNR4_03": ["Ce urmează în șirul: 15, 21, 28, 36, 45, ?", "Acestea sunt triangular numbers. Diferențele dintre termeni increase by 1 la fiecare pas.", ["55", "54", "56", "50"], "Acestea sunt numere triunghiulare T(5) până la T(10). Diferențele sunt 6, 7, 8, 9, so the next difference is 10: 45 + 10 = 55."],
    "TNR4_04": ["Ce urmează în șirul: 36, 45, 55, 66, 78, ?", "Calculează diferențele. Ele cresc cu 1 de fiecare dată — semnul numerelor triunghiulare.", ["91", "88", "90", "84"], "Acestea sunt numere triunghiulare T(8) până la T(13). Diferențele sunt 9, 10, 11, 12, so the next difference is 13: 78 + 13 = 91."],
    "TNR4_05": ["Ce urmează în șirul: 1, 5, 13, 29, 61, ?", "Încearcă să dublezi termenul anterior și să aduni o constantă mică.", ["125", "122", "123", "127"], "Fiecare termen respectă regula: previous × 2 + 3. Următorul termen este 61 × 2 + 3 = 125."],
    "TNR4_06": ["Ce urmează în șirul: 1, 2, 5, 14, 41, ?", "Încearcă să înmulțești termenul anterior cu 3 și să ajustezi.", ["122", "120", "123", "82"], "Fiecare termen respectă regula: previous × 3 − 1. Următorul termen este 41 × 3 − 1 = 122."],
    "TNR4_07": ["Ce urmează în șirul: 2, 9, 23, 51, 107, ?", "Dublează termenul anterior și adună o constantă pentru următorul.", ["219", "214", "215", "221"], "Fiecare termen respectă regula: previous × 2 + 5. Următorul termen este 107 × 2 + 5 = 219."],
    "TNR4_08": ["Ce urmează în șirul: 9, 25, 49, 121, 169, ?", "Take the square root of each term, apoi think about what makes those numbers special.", ["289", "225", "256", "324"], "Acestea sunt squares of consecutive primes: 3²=9, 5²=25, 7²=49, 11²=121, 13²=169, 17²=289."],
    "TNR4_09": ["Ce urmează în șirul: 10, 11, 15, 24, 40, ?", "Găsește diferențele dintre termeni. Sunt aceste diferențe un șir cunoscut?", ["65", "56", "64", "60"], "Diferențele sunt 1, 4, 9, 16 — perfect squares (1², 2², 3², 4²). Următoarea diferență este 5²=25, so 40 + 25 = 65."],
    "TNR4_10": ["Ce urmează în șirul: 0, 1, 3, 9, 33, ?", "Calculează diferențele dintre termeni. Îți amintesc aceste diferențe de un șir celebru?", ["153", "129", "150", "57"], "Diferențele sunt 1, 2, 6, 24 — these are factorials (1!, 2!, 3!, 4!). Următoarea diferență este 5!=120, so 33 + 120 = 153."],
    "TNR4_11": ["Ce urmează în șirul: 2, 7, 22, 67, 202, ?", "Înmulțește termenul anterior cu un număr și adună o constantă.", ["607", "606", "605", "610"], "Fiecare termen respectă regula: previous × 3 + 1. Următorul termen este 202 × 3 + 1 = 607."],
    "TNR4_12": ["Ce urmează în șirul: 20, 37, 71, 139, 275, ?", "Încearcă să dublezi termenul anterior și să scazi o constantă mică.", ["547", "550", "545", "553"], "Fiecare termen respectă regula: previous × 2 − 3. Următorul termen este 275 × 2 − 3 = 547."],
    "TNR4_13": ["Ce urmează în șirul: 1, 5, 14, 30, 55, ?", "Diferențele dintre termeni are perfect squares. Sum up consecutive squares.", ["91", "85", "90", "80"], "Acestea sunt cumulative sums of squares: 1, 1+4=5, 5+9=14, 14+16=30, 30+25=55, 55+36=91."],
    "TNR4_14": ["Ce urmează în șirul: 2, 4, 12, 48, 240, ?", "Încearcă să împarți fiecare termen la 2. Rezultatele seamănă cu factoriali?", ["1440", "1200", "1680", "960"], "Fiecare termen este egal cu 2 × n!: 2×1!=2, 2×2!=4, 2×3!=12, 2×4!=48, 2×5!=240, 2×6!=1440."],
    "TNR4_15": ["Ce urmează în șirul: 6, 13, 27, 55, 111, ?", "Dublează termenul anterior și adună o constantă la fiecare pas.", ["223", "222", "220", "225"], "Fiecare termen respectă regula: previous × 2 + 1. Următorul termen este 111 × 2 + 1 = 223."],
    "TNR4_16": ["Ce urmează în șirul: 10, 11, 14, 20, 30, ?", "Diferențele dintre termeni are triangular numbers: 1, 3, 6, 10, …", ["45", "40", "42", "50"], "Diferențele sunt 1, 3, 6, 10 — numere triunghiulare. Următorul număr triunghiular este 15, deci 30 + 15 = 45."],
    "TNR4_17": ["Ce urmează în șirul: 12, 20, 30, 42, 56, ?", "Încearcă să exprimi fiecare termen ca a product of two consecutive integers.", ["72", "68", "70", "64"], "Acestea sunt oblong numbers n(n+1): 3×4=12, 4×5=20, 5×6=30, 6×7=42, 7×8=56, 8×9=72."],
    "TNR4_18": ["Ce urmează în șirul: 1, 9, 36, 100, 225, ?", "Fiecare termen este the square of a triangular number, or equivalently the cumulative sum of cubes.", ["441", "400", "440", "450"], "Acestea sunt sums of consecutive cubes: 1³=1, 1+8=9, 9+27=36, 36+64=100, 100+125=225, 225+216=441."],
    "TNR4_19": ["Ce urmează în șirul: 3, 7, 19, 55, 163, ?", "Înmulțește termenul anterior cu un număr și scade o constantă.", ["487", "489", "485", "492"], "Fiecare termen respectă regula: previous × 3 − 2. Următorul termen este 163 × 3 − 2 = 487."],
    "TNR4_20": ["Ce urmează în șirul: 12, 23, 45, 89, 177, ?", "Dublează termenul anterior și fă o mică ajustare.", ["353", "354", "355", "350"], "Fiecare termen respectă regula: previous × 2 − 1. Următorul termen este 177 × 2 − 1 = 353."],
    "TNR5_01": ["Ce urmează în șirul: 1, 2, 9, 64, 625, ?", "Gândește-te la ce putere este ridicată baza fiecărei poziții.", ["7776", "7774", "7200", "3125"], "Fiecare termen este n ridicat la puterea (n−1): 1⁰=1, 2¹=2, 3²=9, 4³=64, 5⁴=625, 6⁵=7776."],
    "TNR5_02": ["Ce urmează în șirul: 2, 10, 30, 68, 130, ?", "Încearcă să descompui fiecare termen într-o parte cubică și una liniară.", ["222", "220", "218", "216"], "Fiecare termen este egal cu n³ + n: 1+1=2, 8+2=10, 27+3=30, 64+4=68, 125+5=130, 216+6=222."],
    "TNR5_03": ["Ce urmează în șirul: 1, 1, 2, 5, 14, ?", "Acestea sunt numerele Catalan. Each C(n) = C(0)C(n−1) + C(1)C(n−2) + … + C(n−1)C(0).", ["42", "28", "35", "48"], "Acestea sunt Catalan numbers: C(0)=1, C(1)=1, C(2)=2, C(3)=5, C(4)=14, C(5)=42."],
    "TNR5_04": ["Ce urmează în șirul: 1, 5, 12, 22, 35, ?", "Diferențele sunt 4, 7, 10, 13 — an arithmetic sequence with step 3.", ["51", "48", "50", "55"], "Acestea sunt pentagonal numbers: n(3n−1)/2. Pentru n=6: 6×17/2 = 51."],
    "TNR5_05": ["Ce urmează în șirul: 2, 5, 13, 35, 97, ?", "Încearcă să exprimi fiecare termen ca a sum of two exponential expressions.", ["275", "265", "270", "280"], "Fiecare termen este egal cu 2ⁿ + 3ⁿ (starting from n=0): 1+1=2, 2+3=5, 4+9=13, 8+27=35, 16+81=97, 32+243=275."],
    "TNR5_06": ["Ce urmează în șirul: 1, 5, 17, 53, 161, ?", "Multiply the previous term by 3 și add a small constant.", ["485", "483", "322", "487"], "Fiecare termen respectă regula: previous × 3 + 2. Următorul termen este 161 × 3 + 2 = 485."],
    "TNR5_07": ["Ce urmează în șirul: 1, 2, 5, 12, 27, ?", "Gândește-te la puteri ale lui 2, apoi scade ceva ce depinde de poziție.", ["58", "54", "56", "60"], "Fiecare termen este egal cu 2ⁿ − n: 2¹−1=1, 2²−2=2, 2³−3=5, 2⁴−4=12, 2⁵−5=27, 2⁶−6=58."],
    "TNR5_08": ["Ce urmează în șirul: 2, 12, 36, 80, 150, ?", "Încearcă să factorizezi fiecare termen în n² ori ceva.", ["252", "240", "250", "260"], "Fiecare termen este egal cu n²(n+1): 1×2=2, 4×3=12, 9×4=36, 16×5=80, 25×6=150, 36×7=252."],
    "TNR5_09": ["Ce urmează în șirul: 1, 6, 15, 28, 45, ?", "Diferențele sunt 5, 9, 13, 17 — increasing by 4. Acestea sunt hexagonal numbers.", ["66", "60", "63", "70"], "Acestea sunt hexagonal numbers: n(2n−1). Pentru n=6: 6×11 = 66."],
    "TNR5_10": ["Ce urmează în șirul: 2, 6, 15, 40, 145, ?", "Încearcă să descompui fiecare termen într-o parte factorială și una pătratică.", ["756", "750", "745", "760"], "Fiecare termen este egal cu n! + n²: 1!+1=2, 2!+4=6, 3!+9=15, 4!+16=40, 5!+25=145, 6!+36=756."],
    "TNR5_11": ["Ce urmează în șirul: 2, 4, 7, 14, 17, ?", "Operațiile alternează între două reguli diferite la pași impari și pari.", ["34", "20", "31", "37"], "Tiparul alternează: ×2, +3, ×2, +3, ×2. Deci 17 × 2 = 34."],
    "TNR5_12": ["Ce urmează în șirul: 1, 5, 19, 65, 211, ?", "Exprimă fiecare termen ca diferență a două valori exponențiale.", ["665", "660", "633", "670"], "Fiecare termen este egal cu 3ⁿ − 2ⁿ: 3−2=1, 9−4=5, 27−8=19, 81−16=65, 243−32=211, 729−64=665."],
    "TNR5_13": ["Ce urmează în șirul: 1, 4, 11, 29, 76, ?", "Fiecare termen depinde de the two terms before it. Try a linear combination.", ["199", "197", "200", "228"], "Regula este a(n) = 3×a(n−1) − a(n−2): 3×29−11=76, 3×76−29=199."],
    "TNR5_14": ["Ce urmează în șirul: 20, 22, 26, 34, 50, ?", "Diferențele sunt 2, 4, 8, 16 — powers of 2.", ["82", "66", "80", "84"], "Diferențele sunt powers of 2: 2, 4, 8, 16. Următoarea diferență este 32, so 50 + 32 = 82."],
    "TNR5_15": ["Ce urmează în șirul: 1, 4, 10, 20, 35, ?", "Acestea sunt tetrahedral numbers — sums of consecutive triangular numbers.", ["56", "50", "55", "60"], "Numere tetraedrice: n(n+1)(n+2)/6. Pentru n=6: 6×7×8/6 = 56."],
    "TNR5_16": ["Ce urmează în șirul: 1, 13, 37, 73, 121, ?", "Diferențele sunt 12, 24, 36, 48 — multiples of 12.", ["181", "169", "175", "193"], "Acestea sunt star numbers: 6n(n−1)+1. Pentru n=6: 6×30+1 = 181."],
    "TNR5_17": ["Ce urmează în șirul: 1, 7, 19, 37, 61, ?", "Diferențele sunt 6, 12, 18, 24 — multiples of 6.", ["91", "85", "90", "97"], "Acestea sunt centered hexagonal numbers: 3n(n−1)+1. Pentru n=6: 3×30+1 = 91."],
    "TNR5_18": ["Ce urmează în șirul: 3, 8, 17, 32, 57, ?", "Încearcă să exprimi fiecare termen ca the sum of a square și a power of 2.", ["100", "96", "98", "105"], "Fiecare termen este egal cu n² + 2ⁿ: 1+2=3, 4+4=8, 9+8=17, 16+16=32, 25+32=57, 36+64=100."],
    "TNR5_19": ["Ce urmează în șirul: 1, 4, 8, 11, 22, ?", "Două operații diferite alternează. Una adună, cealaltă înmulțește.", ["25", "44", "24", "26"], "Tiparul alternează: +3, ×2, +3, ×2, +3. Deci 22 + 3 = 25."],
    "TNR5_20": ["Ce urmează în șirul: 1, 1, 3, 5, 11, ?", "Fiecare termen folosește both of the two preceding terms with different weights.", ["21", "16", "22", "19"], "Regula este a(n) = a(n−1) + 2×a(n−2): 5 + 2×3 = 11, 11 + 2×5 = 21."],
    "TLR1_01": ["Toți medicii sunt profesioniști. Dr. Adams este medic. Ce puteți concluziona?", "Dacă toți X sunt Y și Z este X, atunci Z trebuie să fie Y.", ["Dr. Adams este profesionist", "Dr. Adams nu este profesionist", "Unii profesioniști nu sunt medici", "Toți profesioniștii sunt medici"], "Toți medicii sunt profesioniști, iar Dr. Adams este medic, deci Dr. Adams este profesionist. Silogism afirmativ universal direct."],
    "TLR1_02": ["Toți leii sunt animale. Simba este leu. Ce puteți concluziona?", "Dacă fiecare membru al grupei X aparține grupei Y, iar Simba este în X…", ["Simba este animal", "Toate animalele sunt lei", "Simba nu este animal", "Unele animale nu sunt lei"], "Toți leii sunt animale, iar Simba este leu, deci Simba este animal."],
    "TLR1_03": ["Toate portocalele sunt fructe. Obiectul acesta este portocală. Ce puteți concluziona?", "Dacă fiecare portocală este fruct și obiectul este portocală…", ["Obiectul este fruct", "Toate fructele sunt portocale", "Obiectul este legumă", "Obiectul poate să nu fie fruct"], "Toate portocalele sunt fructe, iar obiectul este portocală, deci este fruct."],
    "TLR1_04": ["Toate mașinile sunt vehicule. O BMW este mașină. Ce puteți concluziona?", "Mașinile sunt o submulțime a vehiculelor. Unde se plasează BMW?", ["BMW este vehicul", "Toate vehiculele sunt mașini", "BMW nu este vehicul", "Unele vehicule nu sunt mașini"], "Toate mașinile sunt vehicule. BMW este mașină, deci BMW este vehicul."],
    "TLR1_05": ["Nicio pasăre nu este insectă. O mierlă este pasăre. Ce puteți concluziona?", "Dacă niciun membru al X nu este în Y, iar mierla este în X…", ["Mierla nu este insectă", "Mierla este insectă", "Unele insecte sunt păsări", "Toate mierlele sunt insecte"], "Nicio pasăre nu este insectă. Mierla este pasăre, deci nu poate fi insectă."],
    "TLR1_06": ["Toată gheața este rece. Cubul de pe masă este din gheață. Ce puteți concluziona?", "Dacă tot ce este gheață este rece, iar cubul este gheață…", ["Cubul este rece", "Cubul este cald", "Nu totă gheața este rece", "Masa este rece"], "Toată gheața este rece, iar cubul este gheață, deci cubul este rece."],
    "TLR1_07": ["Toate viorile sunt instrumente. Un Stradivarius este vioară. Ce puteți concluziona?", "Viorile fac parte din mulțimea instrumentelor. Un Stradivarius aparține…", ["Stradivarius este instrument", "Toate instrumentele sunt viori", "Stradivarius nu este instrument", "Unele instrumente nu pot fi cântate"], "Toate viorile sunt instrumente, iar Stradivarius este vioară, deci este instrument."],
    "TLR1_08": ["Toți trandafirii sunt plante. Exemplarul acesta este trandafir. Ce puteți concluziona?", "Trandafirii sunt submulțime a plantelor. Exemplarul este trandafir, deci…", ["Exemplarul este plantă", "Toate plantele sunt trandafiri", "Exemplarul nu este plantă", "Trandafirii nu sunt plante"], "Toți trandafirii sunt plante, iar exemplarul este trandafir, deci este plantă."],
    "TLR1_09": ["Tot aurul este metalic. Inelul acesta este din aur. Ce puteți concluziona?", "Aurul este întotdeauna metalic. Inelul este din aur, deci…", ["Inelul este metalic", "Tot ce este metalic este din aur", "Inelul nu este metalic", "Aurul este uneori nemetalic"], "Tot aurul este metalic, iar inelul este din aur, deci inelul este metalic."],
    "TLR1_10": ["Toate râurile conțin apă curgătoare. Amazonul este râu. Ce puteți concluziona?", "Dacă fiecare râu are apă curgătoare, iar Amazonul este râu…", ["Amazonul conține apă curgătoare", "Toată apa curgătoare este râu", "Amazonul nu conține apă", "Unele râuri sunt secate"], "Toate râurile conțin apă curgătoare, iar Amazonul este râu, deci Amazonul conține apă curgătoare."],
    "TLR1_11": ["Toate romanele sunt cărți. Toate cărțile au pagini. Ce puteți concluziona?", "Leagă relațiile: romane → cărți → pagini.", ["Toate romanele au pagini", "Toate paginile sunt exclusive în romane", "Unele cărți nu sunt romane", "Romanele nu au pagini"], "Toate romanele sunt cărți, toate cărțile au pagini, deci prin tranzitivitate toate romanele au pagini."],
    "TLR1_12": ["Toți bucătarii știu să gătească. Pierre este bucătar. Ce puteți concluziona?", "Dacă fiecare bucătar știe să gătească, iar Pierre este bucătar…", ["Pierre știe să gătească", "Oricine știe să gătească este bucătar", "Pierre nu știe să gătească", "Unii bucătari nu știu să gătească"], "Toți bucătarii știu să gătească, iar Pierre este bucătar, deci Pierre știe să gătească."],
    "TLR1_13": ["Toți vulturii sunt păsări. Toate păsările au pene. Ce puteți concluziona?", "Leagă mulțimile: vulturi ⊂ păsări ⊂ creaturi cu pene.", ["Toți vulturii au pene", "Toate creaturile cu pene sunt vulturi", "Vulturii nu au pene", "Unele păsări nu sunt vulturi"], "Toți vulturii sunt păsări, toate păsările au pene, deci toți vulturii au pene."],
    "TLR1_14": ["Toate planetele orbitează o stea. Saturn este planetă. Ce puteți concluziona?", "Planetele orbitează stele. Saturn este planetă, deci…", ["Saturn orbitează o stea", "Tot ce orbitează o stea este planetă", "Saturn nu orbitează o stea", "Steaua orbitează Saturnul"], "Toate planetele orbitează o stea, Saturn este planetă, deci Saturn orbitează o stea."],
    "TLR1_15": ["Toate balenele sunt mamifere. Balena albastră este balenă. Ce puteți concluziona?", "Balenele sunt submulțime a mamiferelor. Balena albastră este balenă, deci…", ["Balena albastră este mamifer", "Toate mamiferele sunt balene", "Balena albastră este pește", "Unele balene nu sunt mamifere"], "Toate balenele sunt mamifere, balena albastră este balenă, deci este mamifer."],
    "TLR1_16": ["Niciun ierbivor nu mănâncă carne. Iepurele este ierbivor. Ce puteți concluziona?", "Dacă niciun ierbivor nu mănâncă carne, iar iepurele este ierbivor…", ["Iepurele nu mănâncă carne", "Iepurele mănâncă carne", "Unii ierbivori mănâncă carne", "Toți carnivorii sunt iepuri"], "Ierbivorii nu mănâncă carne, iepurele este ierbivor, deci nu mănâncă carne."],
    "TLR1_17": ["Toți cățeii sunt câini. Toți câinii sunt canide. Ce puteți concluziona?", "Lanț: căței ⊂ câini ⊂ canide.", ["Toți cățeii sunt canizi", "Toți canizii sunt căței", "Cățeii nu sunt canizi", "Unii câini nu sunt canide"], "Toți cățeii sunt câini, toți câinii sunt canide, deci toți cățeii sunt canizi."],
    "TLR1_18": ["Toți profesorii lucrează în educație. Domnul Brown este profesor. Ce puteți concluziona?", "Dacă fiecare profesor lucrează în educație, iar domnul Brown este profesor…", ["Domnul Brown lucrează în educație", "Toți din educație sunt profesori", "Domnul Brown nu lucrează în educație", "Unii profesori nu lucrează în educație"], "Toți profesorii lucrează în educație, domnul Brown este profesor, deci lucrează în educație."],
    "TLR1_19": ["Toate diamantele sunt pietre prețioase. Toate pietrele prețioase sunt valoroase. Ce puteți concluziona?", "Lanț: diamante ⊂ pietre prețioase ⊂ obiecte valoroase.", ["Toate diamantele sunt valoroase", "Toate lucrurile valoroase sunt diamante", "Diamantele nu au valoare", "Unele pietre prețioase nu valorează nimic"], "Toate diamantele sunt pietre prețioase, toate pietrele prețioase sunt valoroase, deci toate diamantele sunt valoroase."],
    "TLR1_20": ["Toate zilele de vară sunt calde. Astăzi este o zi de vară. Ce puteți concluziona?", "Dacă fiecare zi de vară este caldă, iar astăzi este zi de vară…", ["Astăzi e cald", "Toate zilele calde sunt de vară", "Astăzi e frig", "Zilele de vară nu sunt mereu calde"], "Toate zilele de vară sunt calde, astăzi este zi de vară, deci astăzi este cald."],
    "TLR2_01": ["Dacă ninge, temperatura este sub zero. Ninge. Ce puteți concluziona?", "Modus ponens: dacă P→Q și P este adevărat, atunci Q este adevărat.", ["Temperatura este sub zero", "Temperatura este peste zero", "Nu ninge", "Nu se poate trage o concluzie"], "Modus ponens: P→Q (ninsoare → sub zero). P este adevărat, deci Q este adevărat."],
    "TLR2_02": ["Dacă studiezi regulat, notele se îmbunătățesc. Notele tale nu s-au îmbunătățit. Ce puteți concluziona?", "Modus tollens: dacă P→Q și Q este fals, atunci P este fals.", ["Nu ai studiat regulat", "Ai studiat regulat", "Notele s-au îmbunătățit", "Studiul nu influențează notele"], "Modus tollens: P→Q (studiu regulat → note mai bune). Q este fals, deci P este fals."],
    "TLR2_03": ["Dacă telefonul este complet încărcat, ține toată ziua. Telefonul tău este complet încărcat. Ce puteți concluziona?", "Antecedentul este adevărat — se aplică modus ponens.", ["Telefonul va ține toată ziua", "Telefonul nu va ține toată ziua", "Telefonul nu este încărcat", "Nu se poate trage o concluzie"], "Modus ponens: P→Q (încărcat → ține ziua întreagă). P este adevărat, deci Q este adevărat."],
    "TLR2_04": ["Dacă alarma este setată, sună la 7 dimineața. Alarma nu a sunat la 7. Ce puteți concluziona?", "Consecința este falsă — aplică modus tollens.", ["Alarma nu era setată", "Alarma era setată", "Alarma a sunat la 7", "Alarma este stricată"], "Modus tollens: P→Q (alarmă setată → sună la 7). Q este fals, deci P este fals."],
    "TLR2_05": ["Dacă ai cheia corectă, încuietoarea se deschide. Ai cheia corectă. Ce puteți concluziona?", "Antecedentul este îndeplinit — modus ponens.", ["Încuietoarea se deschide", "Încuietoarea nu se deschide", "Nu ai cheia corectă", "Încuietoarea este blocată"], "Modus ponens: P→Q (cheie corectă → deschidere). P este adevărat, deci Q este adevărat."],
    "TLR2_06": ["Dacă curentul este pus, frigiderul funcționează. Frigiderul nu funcționează. Ce puteți concluziona?", "Consecința este falsă — modus tollens.", ["Curentul nu este pus", "Curentul este pus", "Frigiderul funcționează", "Nu se poate trage o concluzie"], "Modus tollens: P→Q (curent pornit → frigiderul merge). Q este fals, deci P este fals."],
    "TLR2_07": ["Dacă uzi plantele zilnic, rămân verzi. Le uzi zilnic. Ce puteți concluziona?", "Condiția este îndeplinită — ce urmează?", ["Plantele tale rămân verzi", "Plantele se ofilesc", "Nu le uzi", "Udarea nu are efect"], "Modus ponens: P→Q (udat zilnic → rămân verzi). P este adevărat, deci Q este adevărat."],
    "TLR2_08": ["Dacă mașina are combustibil, motorul poate porni. Motorul nu pornește. Ce puteți concluziona?", "Rezultatul nu s-a produs — aplică modus tollens.", ["Mașina nu are combustibil", "Mașina are combustibil", "Motorul a pornit", "Nu se poate trage o concluzie"], "Modus tollens: P→Q (combustibil → motorul pornește). Q este fals, deci P este fals."],
    "TLR2_09": ["Dacă cumperi bilet, poți urca în tren. Ai cumpărat bilet. Ce puteți concluziona?", "Ai îndeplinit condiția — care este pasul următor?", ["Poți urca în tren", "Nu poți urca în tren", "Nu ai cumpărat bilet", "Trenul este anulat"], "Modus ponens: P→Q (bilet → urci în tren). P este adevărat, deci Q este adevărat."],
    "TLR2_10": ["Dacă ai pașaport valabil, poți traversa frontiera. Nu poți traversa frontiera. Ce puteți concluziona?", "Dacă P→Q și Q este fals, ce înseamnă pentru P?", ["Nu ai pașaport valabil", "Ai pașaport valabil", "Ai traversat frontiera", "Nu e nevoie de pașaport"], "Modus tollens: P→Q (pașaport → traversezi). Q este fals, deci P este fals."],
    "TLR2_11": ["Dacă un animal este cal, are patru picioare. Acest animal are patru picioare. Ce puteți concluziona?", "Adevărul consecinței nu dovedește antecedentul. Multe animale au patru picioare.", ["Nu putem concluziona că e cal", "Sigur este cal", "Are două picioare", "Nu este animal"], "Eroarea afirmării consecinței: P→Q (cal → patru picioare) și Q adevărat nu implică P. Multe animale care nu sunt cai au patru picioare."],
    "TLR2_12": ["Dacă cineva este avocat, a studiat dreptul. Sam a studiat dreptul. Ce puteți concluziona?", "Numai pentru că Q este adevărat nu înseamnă că P este adevărat.", ["Nu putem concluziona că Sam este avocat", "Sam este cu siguranță avocat", "Sam nu a studiat dreptul", "Toți cei care au studiat dreptul sunt avocați"], "Afirmarea consecinței: P→Q (avocat → a studiat drept) și Q adevărat nu dovedește că Sam este avocat."],
    "TLR2_13": ["Dacă cuptorul este pornit, bucătăria se încălzește. Bucătăria nu este caldă. Ce puteți concluziona?", "Consecința este falsă — modus tollens.", ["Cuptorul nu este pornit", "Cuptorul este pornit", "Bucătăria este caldă", "Nu se poate trage o concluzie"], "Modus tollens: P→Q (cuptor pornit → bucătăria se încălzește). Q este fals, deci P este fals."],
    "TLR2_14": ["Dacă apeși frâna, mașina încetinește. Ai apăsat frâna. Ce puteți concluziona?", "Antecedentul este adevărat — modus ponens.", ["Mașina încetinește", "Mașina accelerează", "Nu ai apăsat frâna", "Nu se întâmplă nimic"], "Modus ponens: P→Q (frână → încetinire). P este adevărat, deci Q este adevărat."],
    "TLR2_15": ["Dacă ninge, cerul este înnorat. Cerul este înnorat. Ce puteți concluziona?", "Cerul poate fi innorat fără ninsoare — este oare afirmarea consecinței?", ["Nu putem concluziona că ningă", "Cu siguranță ningă", "Cerul este senin", "Nu ningă niciodată când e innorat"], "Afirmarea consecinței: P→Q și Q nu implică P. Cerul poate fi acoperit fără ninsoare."],
    "TLR2_16": ["Dacă bateria este încărcată, lanterna funcționează. Lanterna nu funcționează. Ce puteți concluziona?", "Q este fals — ce spune asta despre P?", ["Bateria nu este încărcată", "Bateria este încărcată", "Lanterna funcționează", "Nu se poate trage o concluzie"], "Modus tollens: P→Q (încărcat → funcționează). Q este fals, deci P este fals."],
    "TLR2_17": ["Dacă pui zahăr în ceai, ceaiul devine dulce. Ai pus zahăr în ceai. Ce puteți concluziona?", "Condiția este îndeplinită — modus ponens.", ["Ceaiul devine dulce", "Ceaiul rămâne amar", "Nu ai pus zahăr", "Zahărul nu are efect"], "Modus ponens: P→Q (zahăr → dulce). P este adevărat, deci Q este adevărat."],
    "TLR2_18": ["Dacă ruterul Wi-Fi este pornit, dispozitivele se pot conecta la internet. Dispozitivele nu se pot conecta. Ce puteți concluziona?", "Q este fals — modus tollens.", ["Ruterul Wi-Fi nu este pornit", "Ruterul Wi-Fi este pornit", "Dispozitivele se pot conecta", "Internetul nu există"], "Modus tollens: P→Q (ruter pornit → conexiune). Q este fals, deci P este fals."],
    "TLR2_19": ["Dacă un student se înscrie la curs, primește programa. Emma s-a înscris la curs. Ce puteți concluziona?", "Emma a îndeplinit condiția — care este pasul următor?", ["Emma primește programa", "Emma nu primește programa", "Emma nu s-a înscris", "Cursul nu are orar"], "Modus ponens: P→Q (înscris → primește programa). P este adevărat pentru Emma, deci Q este adevărat."],
    "TLR2_20": ["Dacă este duminică, magazinul este închis. Nu este duminică. Ce puteți concluziona?", "Antecedentul este fals — nu îți spune dacă Q este adevărat sau fals (negarea antecedentului).", ["Nu putem stabili dacă magazinul este deschis sau închis", "Magazinul este cu siguranță deschis", "Magazinul este cu siguranță închis", "Trebuie să fie sâmbătă"], "Negarea antecedentului este o eroare: din P→Q și P fals nu rezultă nimic sigur despre Q."],
    "TLR3_01": ["Anna este mai înaltă decât Dana. Dana este mai înaltă decât Ben. Ben este mai înalt decât Carl. Cine este cel mai scund?", "Scrie lanțul inegalităților și găsește „baza”.", ["Carl", "Ben", "Dana", "Anna"], "Anna > Dana > Ben > Carl. Carl este cel mai scund."],
    "TLR3_02": ["Felix este mai ușor decât George. Harry este mai greu decât George. Ivan este mai ușor decât Felix. Cine este cel mai greu?", "Ordine: Harry > George > Felix > Ivan.", ["Harry", "George", "Felix", "Ivan"], "Harry > George > Felix > Ivan. Cel mai greu este Harry."],
    "TLR3_03": ["Mia este mai tânără decât Nina. Oscar este mai în vârstă decât Nina. Pam este mai tânără decât Mia. Cine este cel mai în vârstă?", "Clasament: Oscar > Nina > Mia > Pam.", ["Oscar", "Nina", "Mia", "Pam"], "Oscar > Nina > Mia > Pam. Cel mai în vârstă este Oscar."],
    "TLR3_04": ["Într-o cursă, Raj termină după Sam. Tina termină înaintea lui Sam. Uma termină după Raj. Cine termină primul?", "Înainte = mai rapid. Lanț: Tina → Sam → Raj → Uma.", ["Tina", "Sam", "Raj", "Uma"], "Ordinea sosirii: Tina, Sam, Raj, Uma. Prima este Tina."],
    "TLR3_05": ["Victor câștigă mai puțin decât Wendy. Wendy câștigă mai puțin decât Xavier. Yara câștigă mai mult decât Xavier. Cine câștigă cel mai mult?", "Lanț: Victor < Wendy < Xavier < Yara.", ["Yara", "Xavier", "Wendy", "Victor"], "Yara > Xavier > Wendy > Victor. Cel mai mult câștigă Yara."],
    "TLR3_06": ["Eve are scor mai mare decât Frank. Grace are scor mai mic decât Frank. Dave are scor mai mare decât Eve. Cine are cel mai mic scor?", "Dave > Eve > Frank > Grace. Cine este jos?", ["Grace", "Frank", "Eve", "Dave"], "Dave > Eve > Frank > Grace. Cel mai mic scor îl are Grace."],
    "TLR3_07": ["Lily înoată mai repede decât Max. Olivia înoată mai repede decât Lily. Noah înoată mai lent decât Max. Cine înoată cel mai lent?", "După viteză: Olivia > Lily > Max > Noah.", ["Noah", "Max", "Lily", "Olivia"], "Olivia > Lily > Max > Noah. Cel mai lent este Noah."],
    "TLR3_08": ["Quinn este mai scundă decât Ruth. Steve este mai înalt decât Tom. Tom este mai înalt decât Ruth. Cine este cel mai înalt?", "Lanț: Steve > Tom > Ruth > Quinn.", ["Steve", "Tom", "Ruth", "Quinn"], "Steve > Tom > Ruth > Quinn. Cel mai înalt este Steve."],
    "TLR3_09": ["Amy cântărește mai puțin decât Brian. Clara cântărește mai mult decât Dan. Dan cântărește mai mult decât Brian. Cine este cea mai ușoară?", "Clara > Dan > Brian > Amy.", ["Amy", "Brian", "Dan", "Clara"], "Clara > Dan > Brian > Amy. Cea mai ușoară este Amy."],
    "TLR3_10": ["Jake aleargă mai lent decât Kim. Leo aleargă mai repede decât Mona. Mona aleargă mai repede decât Kim. Cine este al doilea ca viteză?", "Leo > Mona > Kim > Jake. Al doilea?", ["Mona", "Kim", "Leo", "Jake"], "Leo > Mona > Kim > Jake. A doua ca viteză este Mona."],
    "TLR3_11": ["Într-un grup de 20 elevi, 12 joacă tenis și 10 joacă fotbal. Fiecare practică cel puțin un sport. Câți practică ambele?", "Ambele = A + B − total (când fiecare face cel puțin unul).", ["2", "4", "8", "10"], "12 + 10 − 20 = 2. Doi elevi practică ambele sporturi."],
    "TLR3_12": ["Într-un grup de 25 persoane, 18 plac cafeaua și 13 ceaiul. Fiecare place cel puțin una. Câte persoane plac ambele?", "Ambele = cafea + ceai − total.", ["6", "5", "7", "8"], "18 + 13 − 25 = 6. Șase persoane plac ambele."],
    "TLR3_13": ["Într-o firmă cu 35 angajați, 20 vorbesc franceza și 22 germana. Fiecare vorbește cel puțin una dintre limbi. Câți vorbesc ambele?", "Ambele = franceză + germană − total.", ["7", "5", "8", "13"], "20 + 22 − 35 = 7. Șapte angajați vorbesc ambele limbi."],
    "TLR3_14": ["Într-un grup de 40 turiști, 28 au vizitat muzeul și 18 parcul. Fiecare a vizitat cel puțin un loc. Câți au vizitat ambele?", "Ambele = muzeu + parc − total.", ["6", "10", "8", "4"], "28 + 18 − 40 = 6. Șase turiști au vizitat ambele."],
    "TLR3_15": ["Într-un grup de 30 cititori, 16 citesc ficțiune și 20 non-ficțiune. Fiecare citește cel puțin un tip. Câți citesc ambele?", "Ambele = ficțiune + non-ficțiune − total.", ["6", "4", "10", "14"], "16 + 20 − 30 = 6. Șase cititori citesc ambele tipuri."],
    "TLR3_16": ["Într-un rând de persoane, Alice este a 3-a de la stânga și a 5-a de la dreapta. Câte persoane sunt în rând?", "Total = poziția stânga + poziția dreapta − 1.", ["7", "8", "6", "9"], "3 + 5 − 1 = 7. Sunt 7 persoane în rând."],
    "TLR3_17": ["Într-un rând, Bob este al 7-lea de la stânga și al 4-lea de la dreapta. Câte persoane sunt în rând?", "Total = stânga + dreapta − 1.", ["10", "11", "9", "12"], "7 + 4 − 1 = 10. Sunt 10 persoane în rând."],
    "TLR3_18": ["La coadă, Carol este a 5-a din față și a 9-a din spate. Câte persoane sunt la coadă?", "Total = față + spate − 1.", ["13", "14", "12", "15"], "5 + 9 − 1 = 13. Sunt 13 persoane la coadă."],
    "TLR3_19": ["La coadă, David este al 9-lea din față și al 3-lea din spate. Câte persoane sunt la coadă?", "Total = față + spate − 1.", ["11", "12", "10", "13"], "9 + 3 − 1 = 11. Sunt 11 persoane la coadă."],
    "TLR3_20": ["Într-un rând, Emily este a 6-a de la stânga și a 6-a de la dreapta. Câte persoane sunt în rând?", "Total = stânga + dreapta − 1.", ["11", "12", "10", "13"], "6 + 6 − 1 = 11. Sunt 11 persoane în rând."],
    "TLR4_01": ["Cinci persoane sunt comparate după greutate. E e mai greu decât A, A decât B, C decât D, D decât B, A decât C. Clasează de la cel mai greu la cel mai ușor.", "Construiește lanțul: E > A > C > D > B.", ["E, A, C, D, B", "E, A, D, C, B", "A, E, C, D, B", "E, C, A, D, B"], "E > A > C > D > B. Cel mai greu este E, cel mai ușor B."],
    "TLR4_02": ["Cinci alergători termină o cursă. Sam termină înaintea lui Priya, Priya înaintea lui Quinn, Quinn înaintea lui Tara, Tara înaintea Rosei. Cine termină pe locul 3?", "Lanțul sosirilor: Sam → Priya → Quinn → Tara → Rosa.", ["Quinn", "Priya", "Tara", "Sam"], "Ordinea: Sam, Priya, Quinn, Tara, Rosa. Pe locul 3 este Quinn."],
    "TLR4_03": ["Cinci elevi au scoruri diferite la un test. Jack > Fred > Gina > Iris > Hank. Cine are al doilea cel mai mic scor (penultimul loc)?", "Lanț: J > F > G > I > H. Numără de jos în sus.", ["Iris", "Gina", "Hank", "Fred"], "Al doilea de la coadă (după Hank) este Iris."],
    "TLR4_04": ["Șase sportivi așezați după viteză: Elena > Diana > Ava > Bella > Chloe > Fiona. Sortează de la cel mai rapid la cel mai lent.", "Construiește pas cu pas.", ["Elena, Diana, Ava, Bella, Chloe, Fiona", "Diana, Elena, Ava, Bella, Chloe, Fiona", "Elena, Ava, Diana, Bella, Chloe, Fiona", "Elena, Diana, Bella, Ava, Chloe, Fiona"], "Elena > Diana > Ava > Bella > Chloe > Fiona."],
    "TLR4_05": ["Cinci orașe după populație: Penny > Liam > Mason > Oliver > Noah. Sortează de la cel mai populat la cel mai puțin populat.", "Penny > Liam > Mason > Oliver > Noah.", ["Penny, Liam, Mason, Oliver, Noah", "Liam, Penny, Mason, Oliver, Noah", "Penny, Mason, Liam, Oliver, Noah", "Penny, Liam, Oliver, Mason, Noah"], "Penny > Liam > Mason > Oliver > Noah."],
    "TLR4_06": ["Într-o firmă cu 60 angajați, 38 folosesc Windows și 30 Mac. Fiecare folosește cel puțin un sistem. Câți folosesc ambele?", "Ambele = Windows + Mac − total.", ["8", "10", "12", "6"], "38 + 30 − 60 = 8."],
    "TLR4_07": ["Într-o școală cu 80 elevi, 55 studiază matematica și 42 științele. Fiecare studiază cel puțin o materie. Câți studiază ambele?", "Ambele = matematică + științe − total.", ["17", "15", "20", "23"], "55 + 42 − 80 = 17."],
    "TLR4_08": ["Într-un club cu 75 membri, 50 joacă șah și 40 dame. Fiecare joacă cel puțin un joc. Câți joacă ambele?", "Ambele = șah + dame − total.", ["15", "10", "20", "25"], "50 + 40 − 75 = 15."],
    "TLR4_09": ["Într-un sondaj cu 90 persoane, 60 preferă ciocolata și 52 vanilia. Fiecare place cel puțin un gust. Câte persoane plac ambele?", "Ambele = ciocolată + vanilie − total.", ["22", "18", "30", "12"], "60 + 52 − 90 = 22."],
    "TLR4_10": ["Într-un grup de 100 alegători, 72 susțin propunerea A și 65 propunerea B. Fiecare susține cel puțin una. Câți susțin ambele?", "Ambele = A + B − total.", ["37", "35", "40", "28"], "72 + 65 − 100 = 37."],
    "TLR4_11": ["Într-un sondaj, 50 persoane: 30 au mașină, 25 au bicicletă, 10 au ambele. Câte nu au niciuna?", "Cel puțin una = mașină + bicicletă − ambele. Niciuna = total − cel puțin una.", ["5", "10", "15", "0"], "30 + 25 − 10 = 45 au cel puțin una. 50 − 45 = 5 nu au niciuna."],
    "TLR4_12": ["Într-o clasă de 45 elevi, 28 au trecut matematica, 20 științele, 8 pe ambele. Câți au trecut exact o materie?", "Exact una = (doar mate) + (doar științe).", ["32", "40", "28", "20"], "Doar mate: 28 − 8 = 20. Doar științe: 20 − 8 = 12. Total 32."],
    "TLR4_13": ["Șaizeci de persoane: 40 cântă la chitară, 30 la pian; fiecare cântă la cel puțin un instrument. Câți cântă la un singur instrument?", "Ambele = chitară + pian − 60. Exact unul = cei cu un singur instrument.", ["50", "60", "40", "30"], "Ambele = 10. Exact un singur instrument = 50."],
    "TLR4_14": ["55 studenți: 32 la cenaclul de artă, 28 la muzică, 12 la ambele. Câți nu fac parte din niciun cerc?", "Cel puțin unul = 32 + 28 − 12. Niciunul = 55 − aceasta.", ["7", "5", "10", "3"], "48 au cel puțin un cerc. 55 − 48 = 7."],
    "TLR4_15": ["70 persoane: 45 citesc ziare, 38 reviste, 20 pe ambele. Câte citesc exact un singur tip de lectură?", "Exact unul = (doar ziar) + (doar revistă).", ["43", "63", "50", "33"], "Doar ziar: 45 − 20 = 25. Doar revistă: 38 − 20 = 18. Total 43."],
    "TLR4_16": ["Dacă e frig, Tom poartă pelerină. Dacă poartă pelerină, ia umbrelă. E frig. Ce ia Tom?", "Lanț: frig → pelerină → umbrelă. Modus ponens de două ori.", ["O umbrelă", "O pălărie", "Nimic", "Doar pelerina"], "Frig → pelerină → umbrelă. Deci Tom ia o umbrelă."],
    "TLR4_17": ["Dacă Alice învață, trece examenul. Dacă trece examenul, absolvește. Dacă absolvește, primește ofertă de muncă. Alice învață. Care este rezultatul final?", "Lanț: învățare → promovare → diplomă → ofertă.", ["Alice primește ofertă de muncă", "Alice promovează doar examenul", "Alice tocmai a absolvit", "Nu se poate trage o concluzie"], "Alice parcurge tot lanțul până la oferta de muncă."],
    "TLR4_18": ["Dacă se ia curentul, calculatorul se oprește. Dacă se oprește, munca nesalvată se pierde. Munca nesalvată nu s-a pierdut. Ce concluzionați?", "Modus tollens în lanț: munca nu pierdută → calculatorul nu s-a oprit → curentul nu a dispărut.", ["Curentul nu a dispărut", "Curentul a dispărut", "Calculatorul s-a oprit", "Munca s-a pierdut"], "Munca nesalvată nu e pierdută → calculatorul nu s-a oprit → curentul nu a dispărut."],
    "TLR4_19": ["Dacă plouă, meciul este anulat. Dacă e anulat, biletele se returnează. Biletele nu s-au returnat. Care concluzie?", "Lanț tollens: nu returnate → nu anulat → nu a plouat.", ["Nu a plouat", "A plouat", "Meciul a fost anulat", "Biletele s-au returnat"], "Dublă negare: bilete nereturnate → meci neanulat → nu a plouat."],
    "TLR4_20": ["Dacă mănânci prea mult zahăr, iei în greutate. Dacă iei în greutate, ai nevoie de mai multă mișcare. Dacă ai această nevoie, te abonezi la sală. Nu te-ai abonat la sală. Ce concluzionați?", "Modus tollens în lanț: fără sală → fără nevoie sporită de mișcare → fără creștere în greutate → fără exces de zahăr.", ["Nu ai mâncat prea mult zahăr", "Ai mâncat prea mult zahăr", "Te-ai îngrășat", "Te-ai abonat la sală"], "Fără abonament → fără nevoie sporită de mișcare → fără creștere în greutate → fără exces de zahăr."],
    "TLR5_01": ["Trei persoane: A, B, C. Exact una spune adevărul. A spune: «B și C mint amândoi». B spune: «A minte». C spune: «A spune adevărul». Cine spune adevărul?", "Testează pe rând fiecare ca singura persoană sinceră.", ["B", "A", "C", "Niciuna"], "Dacă B e sincer: A și C mint — nu există contradicție cu „exact una spune adevărul”. Celelalte ipoteze duc la contradicții."],
    "TLR5_02": ["Trei persoane: D, E, F. Exact una spune adevărul. D spune: «E minte». E spune: «F minte». F spune: «D și E mint amândoi». Cine spune adevărul?", "Presupune pe rând fiecare sincer și verifică contradicțiile.", ["E", "D", "F", "Niciuna"], "Dacă E e sincer: F minte; D spune că E minte — deci D minte; afirmația lui F e falsă, deci nu mint amândoi — consistent cu E sincer."],
    "TLR5_03": ["G, H, I — suspecți. Un singur vinovat. Vinovatul minte mereu; nevinovații spun mereu adevărul. G: «H e vinovat». H: «Nu sunt vinovat». I: «G e vinovat». Cine e vinovat?", "Presupune pe rând fiecare vinovat și verifică declarațiile.", ["G", "H", "I", "Nu se poate determina"], "Dacă G e vinovat: G minte → H nevinovat; H zice adevărul; I zice adevărul. Singur vinovat, consistent."],
    "TLR5_04": ["J, K, L. Exact una spune adevărul. J: «Spun adevărul». K: «J spune adevărul». L: «J este mincinos». Cine spune adevărul?", "Dacă J e sincer, și K ar fi sincer — imposibil.", ["L", "J", "K", "Niciuna"], "L sincer → J minte → «spun adevărul» e fals; K minte. Doar L funcționează."],
    "TLR5_05": ["M, N, O. Exact una spune adevărul. M: «N și O spun amândoi adevărul». N: «M minte». O: «N minte». Cine spune adevărul?", "Dacă M ar fi sincer, N și O ar fi sinceri — contrazice „exact una”.", ["N", "M", "O", "Niciuna"], "N sincer → M minte; «N și O amândoi adevărul» e fals → O minte; O minte → «N minte» e fals → N sincer. Consistent."],
    "TLR5_06": ["Peste trei zile va fi miercuri. Ce zi este astăzi?", "Numără înapoi trei zile de la miercuri.", ["Duminică", "Luni", "Sâmbătă", "Marți"], "Astămâna + 3 = miercuri. Astăzi este duminică."],
    "TLR5_07": ["Ieri a fost vineri. Ce zi va fi poimâine?", "Află mai întâi ziua de azi, apoi +2 zile.", ["Luni", "Duminică", "Marți", "Sâmbătă"], "Ieri = vineri → azi = sâmbătă → mâine = duminică → poimâine = luni."],
    "TLR5_08": ["Cu două zile în urmă era luni. Ce zi va fi peste trei zile?", "Află „azi” din „cu două zile în urmă”, apoi adună trei zile.", ["Sâmbătă", "Vineri", "Duminică", "Joi"], "Cu două zile în urmă = luni → azi = miercuri → peste trei zile = sâmbătă."],
    "TLR5_09": ["Alaltăieri a fost joi. Ce zi va fi mâine?", "Alaltăieri = acum două zile. Află azi, apoi +1.", ["Duminică", "Sâmbătă", "Luni", "Vineri"], "Alaltăieri joi → ieri vineri → azi sâmbătă → mâine duminică."],
    "TLR5_10": ["Peste patru zile va fi marți. Ce zi a fost ieri?", "Azi = marți − 4 zile; ieri = azi − 1.", ["Joi", "Vineri", "Miercuri", "Sâmbătă"], "Azi + 4 = marți → azi = vineri. Ieri = joi."],
    "TLR5_11": ["Șase elevi sunt clasați la test: Fay > Diana > Abby > Brian > Carl > Elena. Cine are al treilea cel mai mare scor?", "Construiește lanțul și numără până la poziția 3.", ["Abby", "Diana", "Brian", "Fay"], "Fay > Diana > Abby > Brian > Carl > Elena. Al treilea este Abby."],
    "TLR5_12": ["Cinci borcane au greutăți diferite. Borcanul 5 > 1 > 2 > 4 > 3. Care borcan e la mijloc (locul 3 din 5)?", "Lanț complet 5>1>2>4>3. Mijlocul e poziția 3.", ["Borcanul 2", "Borcanul 1", "Borcanul 4", "Borcanul 3"], "Al treilea în ordine e borcanul 2."],
    "TLR5_13": ["Șapte persoane după vârstă: T>U>V>W>X>Y>Z. Cine e a patra ca vârstă?", "Poziția 4 în lanț.", ["W", "V", "X", "U"], "Al patrulea este W."],
    "TLR5_14": ["Cinci orașe după populație: E>A>B>D>C. Care oraș e cel mai puțin populat?", "C e la coada lanțului.", ["Orașul C", "Orașul D", "Orașul B", "Orașul A"], "Cel mai mic este C."],
    "TLR5_15": ["Șase cărți după numărul de pagini: T>P>Q>U>R>S. Care carte are a doua cele mai puține pagini?", "T>P>Q>U>R>S. A doua de jos = penultima.", ["Cartea R", "Cartea S", "Cartea U", "Cartea Q"], "A doua cele mai puține pagini: R."],
    "TLR5_16": ["Trei cutii etichetate «Mere», «Portocale», «Amestec». Toate etichetele sunt greșite. Alegi un fruct din cutia „Amestec” și e măr. Ce conține de fapt cutia etichetată „Mere»?", "„Amestec” e fals — cutia e omogenă; ai scos măr → acolo sunt merele. Alocă restul.", ["Portocale", "Mere", "Amestec", "Nu se poate determina"], "Cutia „Amestec” nu e amestec; e mere. Cutia „Portocale” nu e portocale → e amestec. Cutia „Mere” nu e mere → e portocale."],
    "TLR5_17": ["Alice, Bob și Carol lucrează în zile diferite: luni, marți, miercuri. Alice nu lucrează luni. Bob nu lucrează marți nici miercuri. Carol nu lucrează miercuri. În ce zi lucrează Carol?", "Începe cu cel mai constrâns: Bob are o singură zi posibilă.", ["Marți", "Luni", "Miercuri", "Nu se poate determina"], "Bob numai luni → Alice marți sau miercuri → Carol nu miercuri → Carol marți. Alice miercuri."],
    "TLR5_18": ["Dacă P e adevărat, Q e adevărat. Dacă Q e adevărat, R e fals. Dacă R e fals, S e adevărat. P e adevărat. Care este valoarea de adevăr a lui S?", "Parcurge lanțul: P → Q → ¬R → S.", ["S e adevărat", "S e fals", "S e necunoscut", "S depinde de R"], "P adevărat → Q adevărat → R fals → S adevărat."],
    "TLR5_19": ["Cinci prieteni după vârstă: Alex > Drew > Blake > Casey > Ellie. Cine e la mijloc (al treilea ca vârstă)?", "Șirul complet; mijlocul din 5 e poziția 3.", ["Blake", "Drew", "Casey", "Alex"], "Al treilea este Blake."],
    "TLR5_20": ["Într-un turneu logic, cinci concurenți (V, W, X, Y, Z) sunt clasați 1–5. V înaintea lui W. X imediat după Y. Z pe locul 3. W pe locul 5. Y înaintea lui Z. Care este locul lui V?", "Z=3, W=5; Y înainte de Z; X imediat după Y.", ["Locul 4", "Locul 1", "Locul 2", "Locul 3"], "Y=1, X=2, Z=3, V=4, W=5. V este pe 4."],
    "TSR1_01": ["Combien de côtés a un pentagone ?", "Le préfixe « penta- » fait référence à un nombre spécifique.", ["5", "4", "6", "7"], "\"Pentagone\" vient du grec pour cinq. Un pentagone a exactement 5 côtés."],
    "TSR1_02": ["Combien de côtés a un hexagone ?", "Le préfixe « hexa- » indique un nombre : pensez à six (comme six côtés).", ["6", "5", "8", "7"], "\"Hexagone\" vient du grec pour six. Un hexagone a 6 côtés."],
    "TSR1_03": ["Combien de côtés a un octogone ?", "Pensez à la pieuvre : combien de bras a-t-elle ?", ["8", "6", "10", "7"], "Le préfixe « octa- » signifie huit, comme dans poulpe. Un octogone a 8 côtés."],
    "TSR1_04": ["Combien d'angles a un triangle ?", "Le préfixe « tri- » vous donne directement la réponse.", ["3", "4", "2", "1"], "Un triangle a 3 angles : un à chaque sommet où deux côtés se rencontrent."],
    "TSR1_05": ["Combien d’angles a un pentagone ?", "Chaque côté rencontre le suivant sous un angle. Comptez les côtés.", ["5", "4", "6", "3"], "Tout polygone a autant d'angles que de côtés. Un pentagone a 5 côtés et 5 angles."],
    "TSR1_06": ["Combien de faces possède une boîte rectangulaire (prisme rectangulaire) ?", "Pensez vers le haut, le bas, l'avant, l'arrière, la gauche et la droite.", ["6", "4", "8", "5"], "Un prisme rectangulaire a 6 faces : haut, bas, avant, arrière, gauche, droite."],
    "TSR1_07": ["Combien de sommets (coins) possède un triangle ?", "Un sommet est l'endroit où deux côtés se rencontrent. Comptez les coins.", ["3", "4", "2", "6"], "Un triangle a 3 sommets, un à chaque coin."],
    "TSR1_08": ["Quelle forme 2D a exactement 3 côtés et 3 angles ?", "C'est l'un des polygones les plus simples.", ["Triangle", "Carré", "Pentagone", "Cercle"], "Un triangle est un polygone ayant 3 côtés et 3 angles."],
    "TSR1_09": ["Si vous pliez une feuille de papier en deux, combien de couches de papier avez-vous ?", "Avant de plier, vous avez 1 couche. Doublez le nombre.", ["2", "1", "3", "4"], "Chaque pli en deux double les couches. En partant de 1, un pli donne 2 couches."],
    "TSR1_10": ["Quelle est la forme de chaque face d’un cube standard ?", "Toutes les faces du cube sont identiques. Quelle forme régulière a 4 côtés égaux et 4 angles droits ?", ["Carré", "Rectangulaire", "Triangle", "Cercle"], "Le cube a 6 faces et chacune est un carré."],
    "TSR1_11": ["Quel corps 3D a le même aspect, quelle que soit la façon dont vous le coupez au centre ?", "Il n’a ni arêtes, ni sommets, il est parfaitement rond.", ["Sphère", "Cylindre", "Cône", "Cube"], "La sphère est parfaitement symétrique. Toute coupe passant par le centre donne un cercle identique."],
    "TSR1_12": ["Combien de côtés droits a un cercle ?", "Le cercle est courbé partout. Y a-t-il des côtés droits ?", ["0", "1", "2", "Infini"], "Le cercle n'a pas de côtés droits : c'est une courbe continue sans coins ni segments droits."],
    "TSR1_13": ["Combien de côtés a un triangle ?", "Le nom dit : « tri » signifie trois.", ["3", "2", "4", "5"], "Un triangle est un polygone ayant exactement 3 côtés."],
    "TSR1_14": ["Combien de côtés a un carré ?", "Pensez à une fenêtre ou à un damier.", ["4", "3", "5", "6"], "Un carré a 4 côtés égaux et 4 angles droits."],
    "TSR1_15": ["Combien de sommets (coins) possède un carré ?", "Comptez les points où deux côtés se rencontrent.", ["4", "3", "5", "6"], "Le carré a 4 sommets, un à chaque coin."],
    "TSR1_16": ["Combien de sommets possède un hexagone ?", "Un polygone a toujours autant de sommets que de côtés.", ["6", "5", "8", "4"], "L'hexagone a 6 côtés, donc 6 sommets."],
    "TSR1_17": ["Si vous pliez une feuille en deux deux fois, combien de couches obtenez-vous ?", "Chaque pli double le nombre actuel de couches.", ["4", "2", "3", "8"], "Premier pli : 1 → 2 couches. Deuxièmement : 2 → 4 couches."],
    "TSR1_18": ["Quelle forme a 4 côtés, tous angles à 90° et côtés opposés parallèles ?", "C’est la forme la plus courante pour les portes, les paravents et les livres.", ["Rectangulaire", "Trapèze", "Losange", "Parallélogramme"], "Le rectangle a 4 côtés, parallèles opposés, tous angles intérieurs 90°."],
    "TSR1_19": ["Combien de coins a un rectangle ?", "Un coin est l'endroit où deux côtés se rencontrent selon un angle.", ["4", "2", "3", "5"], "Le rectangle a 4 coins (sommets), un à chaque angle droit."],
    "TSR1_20": ["Quelle forme 2D a tous les points du contour à la même distance du centre ?", "Pensez à une pièce de monnaie vue d'en haut ou à une pizza.", ["Cercle", "Ellipses", "Carré", "Ovale"], "Un cercle est l'ensemble des points équidistants du centre. Cette distance constante est le rayon."],
    "TSR2_01": ["Combien de côtés a un prisme rectangulaire (boîte) ?", "Comptez les bords supérieurs et inférieurs des faces et les bords verticaux qui les relient.", ["12", "8", "10", "6"], "Prisme rectangulaire : 4 bords supérieurs + 4 inférieurs + 4 verticaux = 12 bords."],
    "TSR2_02": ["Combien de sommets possède un prisme rectangulaire ?", "Comptez séparément les coins supérieurs et inférieurs de la face.", ["8", "6", "10", "12"], "4 sommets en haut + 4 sommets en bas = 8 sommets."],
    "TSR2_03": ["Combien de faces possède un prisme pentagonal ?", "Un prisme de base à n côtés a n faces rectangulaires latérales plus 2 bases.", ["7", "5", "10", "6"], "2 bases pentagonales + 5 faces rectangulaires latérales = 7 faces."],
    "TSR2_04": ["Combien d’arêtes possède un prisme triangulaire ?", "Comptez les bords de chaque base triangulaire, puis les bords qui les relient.", ["9", "6", "8", "12"], "3 bords vers le haut + 3 vers le bas + 3 verticaux = 9 bords."],
    "TSR2_05": ["Combien de sommets possède un prisme triangulaire ?", "Chaque base triangulaire apporte ses propres sommets.", ["6", "5", "8", "9"], "3 sommets sur chaque base : 3 + 3 = 6 sommets."],
    "TSR2_06": ["Si 4 cubes identiques sont en ligne droite, chacun partageant une face avec le suivant, combien de faces sont visibles au total (y compris la face du bas) ?", "Cela commence par 4×6 faces, puis soustrait les faces cachées à chaque jointure.", ["18", "20", "16", "24"], "4 cubes : 24 faces. 3 jointures × 2 faces cachées = 6. 24 − 6 = 18 visibles."],
    "TSR2_07": ["Combien de faces possède un prisme hexagonal ?", "Le prisme de base n-gon a n + 2 faces.", ["8", "6", "12", "10"], "2 bases hexagonales + 6 faces rectangulaires = 8 faces."],
    "TSR2_08": ["Combien d’arêtes possède un prisme pentagonal ?", "Pour un prisme à base à n côtés : arêtes totales = 3n.", ["15", "10", "12", "20"], "5 vers le haut + 5 vers le bas + 5 verticaux = 3 × 5 = 15 bords."],
    "TSR2_09": ["Combien de sommets possède un prisme pentagonal ?", "Le prisme duplique les sommets du polygone de base.", ["10", "12", "8", "15"], "5 sommets par base × 2 bases = 10 sommets."],
    "TSR2_10": ["Combien d’arêtes possède une pyramide à base carrée ?", "Comptez les bords de la base, puis les bords depuis les coins de la base jusqu'au sommet.", ["8", "5", "6", "10"], "4 bords à la base + 4 bords latéraux vers le haut = 8 bords."],
    "TSR2_11": ["Combien de sommets possède une pyramide à base carrée ?", "N'oubliez pas le sommet au-dessus de la base !", ["5", "4", "6", "8"], "4 sommets à la base + 1 sommet = 5 sommets."],
    "TSR2_12": ["Combien de faces possède une pyramide à base carrée ?", "Comptez la base et chaque face latérale triangulaire.", ["5", "4", "6", "8"], "1 base carrée + 4 faces triangulaires = 5 faces."],
    "TSR2_13": ["Combien d’arêtes possède un prisme hexagonal ?", "Formule : bords = 3 × le nombre de côtés de la base.", ["18", "12", "24", "15"], "6 + 6 + 6 = 3 × 6 = 18 arêtes."],
    "TSR2_14": ["Combien de sommets possède un prisme hexagonal ?", "Chaque base hexagonale comporte 6 coins.", ["12", "8", "6", "18"], "6 sommets par base × 2 bases = 12 sommets."],
    "TSR2_15": ["Si 5 cubes identiques sont alignés, partageant des faces, combien de faces sont visibles au total (y compris celle du bas) ?", "5 cubes = 30 faces. Combien d’articulations et combien de visages chacune cache-t-elle ?", ["22", "20", "24", "26"], "30 faces − 4 joints × 2 = 30 − 8 = 22 visibles."],
    "TSR2_16": ["Combien de faces possède un prisme octogonal ?", "Formule du prisme : n + 2 faces pour une base à n côtés.", ["10", "8", "12", "16"], "2 bases octogonales + 8 faces latérales rectangulaires = 10 faces."],
    "TSR2_17": ["Combien d’arêtes possède un prisme octogonal ?", "Formule : 3n arêtes pour une base à n côtés.", ["24", "16", "20", "32"], "3 × 8 = 24 arêtes."],
    "TSR2_18": ["Combien de sommets possède une pyramide triangulaire (tétraèdre) ?", "Base triangulaire et un point au dessus.", ["4", "3", "5", "6"], "Tétraèdre : 3 sommets à la base + 1 sommet = 4 sommets."],
    "TSR2_19": ["Formule d'Euler : V − E + F = 2 pour les polyèdres convexes (E = nombre d'arêtes). Si un polyèdre a 6 sommets et 12 arêtes, combien de faces a-t-il ?", "Réorganiser : F = 2 − V + E.", ["8", "6", "10", "7"], "F = 2 − 6 + 12 = 8 faces (ex : cube régulier ou octaèdre)."],
    "TSR2_20": ["Combien de diagonales a un carré ?", "Une diagonale relie deux sommets non adjacents. Le carré a 4 sommets.", ["2", "4", "1", "3"], "Le carré a 2 diagonales, chacune reliant des coins opposés."],
    "TSR3_01": ["Un cube 3×3×3 est peint sur toutes ses faces, puis découpé en 27 petits cubes. Combien de cubes ont au moins une face peinte ?", "Seul le cube exactement au centre de la grille 3×3×3 n’a pas de peinture. Combien de cubes ne sont pas au centre ?", ["26", "24", "20", "27"], "Un seul cube (le centre) a 0 faces peintes. Donc 27 − 1 = 26 ont au moins un visage peint."],
    "TSR3_02": ["Un cube 3×3×3 est peint sur toutes ses faces et découpé en 27 petits cubes. Combien de faces d’unités peintes les 27 cubes ont-ils au total ?", "Chacune des 6 faces du grand cube est une grille 3×3, donc 9 faces unitaires peintes par face.", ["54", "48", "36", "27"], "6 faces × 9 = 54 faces unitaires peintes."],
    "TSR3_03": ["Le cube 3×3×3 peint est découpé en 27 petits cubes. Combien de cubes ont au plus une face peinte ?", "Comptez les cubes avec 0 faces peintes et exactement 1, puis additionnez.", ["7", "6", "8", "12"], "1 cube à 0 faces (le centre) + 6 cubes à exactement 1 (les centres des faces). Total : 1 + 6 = 7."],
    "TSR3_04": ["Le cube 3×3×3 peint est découpé en 27 petits cubes. Combien de cubes ont au moins 2 faces peintes ?", "Ce sont les cubes de coin (3 côtés) et ceux du bord (2 côtés).", ["20", "12", "8", "18"], "8 coins (3 peints) + 12 bords × 1 cube central à 2 faces = 20 cubes avec 2 faces peintes ou plus."],
    "TSR3_05": ["Si vous coupez un cube avec un plan parallèle à l’une des faces, quelle forme a la section ?", "Couper parallèlement à une face carrée donne une forme conforme à cette face.", ["Carré", "Rectangulaire", "Triangle", "Hexagone"], "Le plan parallèle à une face coupe quatre arêtes égales et donne un carré."],
    "TSR3_06": ["Si vous coupez un cylindre avec un plan perpendiculaire à son axe, quelle forme aura la section ?", "L'axe passe par les centres des deux bases circulaires.", ["Cercle", "Ellipses", "Rectangulaire", "Ovale"], "La coupe perpendiculaire à l'axe est parallèle aux bases — vous obtenez un cercle."],
    "TSR3_07": ["Si vous coupez un cône avec un plan parallèle à la base circulaire, quelle forme obtenez-vous ?", "La base du cône est un cercle. La découpe parallèle donne une forme similaire.", ["Cercle", "Ellipses", "Triangle", "Parabole"], "Le plan parallèle à la base coupe le cône en un cercle (plus petit que la base)."],
    "TSR3_08": ["Combien de sommets possède une sphère ?", "Le sommet est l’endroit où les bords se rejoignent. La sphère a-t-elle des bords ?", ["0", "1", "2", "Infini"], "La sphère est une surface lisse, sans bords, donc sans pics."],
    "TSR3_09": ["Combien d’arêtes possède une sphère ?", "Le bord est le segment où se rencontrent deux faces planes.", ["0", "1", "2", "Infini"], "La sphère n’a pas de faces planes, elle n’a donc pas d’arêtes."],
    "TSR3_10": ["Combien de faces a une pyramide hexagonale ?", "La pyramide a 1 base plus des faces triangulaires latérales – une de chaque côté de la base.", ["7", "6", "8", "12"], "1 base hexagonale + 6 faces triangulaires latérales = 7 faces."],
    "TSR3_11": ["Combien d’arêtes possède une pyramide hexagonale ?", "Comptez les bords de la base et les bords de chaque sommet de la base jusqu'au sommet de la pyramide.", ["12", "6", "8", "18"], "6 bords à la base + 6 bords latéraux vers le haut = 12 bords."],
    "TSR3_12": ["Combien de sommets possède une pyramide hexagonale ?", "Comptez les sommets de la base et le sommet supérieur unique.", ["7", "6", "8", "12"], "6 sommets à la base + 1 sommet = 7 sommets. (Vérification d'Euler : 7 − 12 + 7 = 2 ✓)"],
    "TSR3_13": ["Si vous coupez un cube du milieu d’une arête jusqu’au milieu de l’arête parallèle opposée, quelle forme la section peut-elle avoir ?", "La coupe entre deux arêtes parallèles donne un quadrilatère plan.", ["Rectangulaire", "Triangle", "Pentagone", "Cercle"], "Le plan passant par les milieux de deux arêtes parallèles opposées donne une section rectangulaire."],
    "TSR3_14": ["Combien de faces possède une pyramide à base pentagonale ?", "1 socle + faces latérales (une par côté du socle).", ["6", "5", "7", "10"], "1 base pentagonale + 5 faces triangulaires = 6 faces."],
    "TSR3_15": ["Combien d’arêtes possède une pyramide à base pentagonale ?", "Pour pyramide à base à n côtés : 2n arêtes.", ["10", "5", "8", "15"], "5 bords à la base + 5 côtés = 10 bords."],
    "TSR3_16": ["Combien de sommets possède une pyramide à base pentagonale ?", "Les sommets de la base plus le sommet supérieur.", ["6", "5", "7", "10"], "5 sommets à la base + 1 sommet = 6 sommets. (Vérifiez : 6 − 10 + 6 = 2 ✓)"],
    "TSR3_17": ["En utilisant la formule d'Euler (V − E + F = 2), si un polyèdre a 5 sommets et 8 arêtes, combien de faces a-t-il ?", "Résolvez F : F = 2 − V + E.", ["5", "4", "6", "7"], "F = 2 − 5 + 8 = 5 (ex : pyramide à base carrée : 5 sommets, 8 arêtes, 5 faces)."],
    "TSR3_18": ["Combien de diagonales possède un hexagone régulier ?", "Pour un polygone à n côtés : n(n − 3) / 2.", ["9", "6", "12", "3"], "Diagonales = 6 × (6 − 3) / 2 = 9."],
    "TSR3_19": ["Dans un cube peint 3×3×3 découpé en 27 cubes, combien de faces peintes au total ont seuls les 8 cubes de coin ?", "Chaque cube de coin a exactement 3 faces peintes.", ["24", "8", "12", "18"], "8 coins × 3 faces = 24 faces peintes aux coins."],
    "TSR3_20": ["Combien de diagonales possède un pentagone régulier ?", "Utilisez n(n − 3) / 2 avec n = 5.", ["5", "4", "6", "3"], "Diagonales = 5 × (5 − 3) / 2 = 5."],
    "TSR4_01": ["Un cube 4×4×4 est peint sur toutes ses faces, puis découpé en 64 petits cubes. Combien de cubes ont au moins une face peinte ?", "L'intérieur non peint forme un cube plus petit de côté (4 − 2) = 2.", ["56", "48", "52", "60"], "Cubes avec 0 peinture à l'intérieur = 2³ = 8. Avec au moins 1 face peinte : 64 − 8 = 56."],
    "TSR4_02": ["Le cube 4×4×4 peint est découpé en 64 petits cubes. Combien de cubes ont au moins 2 faces peintes ?", "Cubes d'angle (3 faces) et cubes de bord (2 faces). Collectionnez-les.", ["32", "24", "36", "28"], "Coins : 8. Bords : 12 × 2 cubes moyens = 24. Total : 8 + 24 = 32."],
    "TSR4_03": ["Le cube 4×4×4 peint est découpé en 64 petits cubes. Combien de faces d’unités peintes tous les cubes ont-ils au total ?", "Chacune des 6 faces du grand cube est une grille 4×4.", ["96", "64", "72", "108"], "6 × 16 = 96. (Vérifiez : 8 × 3 + 24 × 2 + 24 × 1 = 96 ✓)"],
    "TSR4_04": ["Le cube 4×4×4 peint est découpé en 64 petits cubes. Combien de cubes ont au plus une face peinte ?", "Ajoutez les cubes avec 0 faces peintes et exactement 1.", ["32", "24", "28", "36"], "0 face peinte : 8 (intérieur 2×2×2). 1 face peinte : 24 (centres des faces). Total : 32."],
    "TSR4_05": ["Si vous supprimez un cube de coin d'un cube 3×3×3, combien de faces des cubes unités sont visibles sur le solide restant (y compris le fond) ?", "En supprimant le coin vous perdez 3 faces extérieures mais révélez 3 faces intérieures précédemment cachées.", ["54", "51", "57", "48"], "Superficie initiale : 6 × 9 = 54. Au coin : −3 extérieur + 3 nouvellement visibles intérieur = 0 net. La surface totale reste 54."],
    "TSR4_06": ["Combien de diagonales possède un octogone régulier ?", "Formule n(n − 3) / 2 avec n = 8.", ["20", "16", "24", "8"], "Diagonales = 8 × 5 / 2 = 20."],
    "TSR4_07": ["Combien de diagonales spatiales possède un cube ? (La diagonale spatiale traverse l’intérieur d’un sommet au sommet opposé.)", "Le cube a 8 sommets. Chaque diagonale spatiale relie un sommet à son opposé.", ["4", "6", "8", "12"], "Le cube a 4 diagonales spatiales, chacune passant par le centre."],
    "TSR4_08": ["Combien de diagonales de faces un cube possède-t-il au total ?", "Chaque visage est carré. Combien de diagonales le carré a-t-il ? Multipliez par 6.", ["12", "6", "8", "24"], "6 faces × 2 diagonales = 12 diagonales en faces."],
    "TSR4_09": ["Combien de faces possède un octaèdre régulier (deux pyramides carrées collées ensemble à la base) ?", "Chaque pyramide apporte 4 faces triangulaires. La base carrée commune se trouve à l’intérieur.", ["8", "6", "12", "20"], "L'octaèdre régulier possède 8 faces triangulaires équilatérales."],
    "TSR4_10": ["Combien d’arêtes possède un octaèdre régulier ?", "Utilisez la formule d'Euler si vous connaissez V = 6 et F = 8.", ["12", "8", "6", "24"], "E = V + F − 2 = 6 + 8 − 2 = 12 arêtes."],
    "TSR4_11": ["Combien de sommets possède un octaèdre régulier ?", "Pensez à deux pyramides reliées à la base. Comptez les sommets distincts.", ["6", "8", "12", "4"], "4 sommets autour de l'équateur carré + 1 sommet vers le haut + 1 vers le bas = 6."],
    "TSR4_12": ["Si 8 cubes unitaires forment un cube 2×2×2, combien de faces des cubes unitaires sont visibles à l’extérieur (y compris le bas) ?", "Le résultat est un cube de côté 2. Superficie totale en faces unitaires ?", ["24", "28", "32", "20"], "6 × (2 × 2) = 24 faces unitaires."],
    "TSR4_13": ["Un dodécaèdre régulier possède 12 faces pentagonales et 30 arêtes. Avec la formule d'Euler, combien de sommets a-t-il ?", "V = 2 + E - F.", ["20", "12", "24", "30"], "V = 2 + 30 − 12 = 20 sommets."],
    "TSR4_14": ["Un icosaèdre régulier possède 20 faces triangulaires et 12 sommets. Combien de bords a-t-il ?", "E = V + F − 2.", ["30", "20", "24", "36"], "E = 12 + 20 − 2 = 30 arêtes."],
    "TSR4_15": ["Dans un cube peint 4×4×4, combien de faces peintes les 8 cubes de coin ont-ils au total ?", "Tout cube de coin a exactement 3 faces peintes, quelle que soit la taille du grand cube.", ["24", "8", "12", "32"], "8 × 3 = 24."],
    "TSR4_16": ["Dans le même cube 4×4×4, combien de faces peintes les cubes de bord (ceux avec exactement 2 faces peintes) ont-ils ?", "Combien y a-t-il de cubes sur les bords, puis multipliez par 2.", ["48", "24", "36", "60"], "24 cubes sur arêtes (12 arêtes × 2), chacun avec 2 faces peintes : 24 × 2 = 48."],
    "TSR4_17": ["Si on coupe un cube avec un plan au moyen de trois arêtes partant du même sommet, quelle forme a la section ?", "Les trois points milieux sont à égale distance du sommet. Quel triangle a tous ses côtés égaux ?", ["Triangle équilatéral", "Carré", "Triangle rectangle", "Hexagone régulier"], "Le plan coupe les trois bords de manière égale : vous obtenez un triangle équilatéral."],
    "TSR4_18": ["Combien de diagonales possède un décagone régulier (10 côtés) ?", "Formule : n(n − 3) / 2.", ["35", "30", "40", "25"], "10 × 7/2 = 35."],
    "TSR4_19": ["Un prisme a exactement 10 sommets. Quelle est la forme de la base ?", "Le prisme de base à n côtés a 2n sommets.", ["Pentagone", "Carré", "Hexagone", "Triangle"], "2n = 10 → n = 5. La base est un pentagone."],
    "TSR4_20": ["Une pyramide a exactement 7 faces. Quelle est la forme de la base ?", "La pyramide de base à n côtés a n + 1 faces.", ["Hexagone", "Pentagone", "Heptagone", "Octogone"], "n + 1 = 7 → n = 6. La base est un hexagone."],
    "TSR5_01": ["Un cube 5×5×5 est peint sur toutes ses faces, puis découpé en 125 petits cubes. Combien de cubes ont exactement 2 faces peintes ?", "Les cubes sur les bords (et non les coins) ont 2 faces peintes. Formule : 12(n − 2).", ["36", "24", "48", "30"], "12 × (5 − 2) = 36."],
    "TSR5_02": ["Le cube 5×5×5 peint est découpé en 125 petits cubes. Combien de cubes ont exactement 3 faces peintes ?", "Seuls les cubes de coin ont 3 faces peintes. Combien de coins possède un cube ?", ["8", "12", "20", "6"], "Tout cube a 8 coins. Donc 8 cubes avec exactement 3 faces peintes."],
    "TSR5_03": ["Le cube 5×5×5 peint est découpé en 125 petits cubes. Combien de cubes ont au moins une face peinte ?", "Soustrayez les cubes à l'intérieur complètement non peints : (n − 2)³.", ["98", "96", "100", "90"], "À l'intérieur = 3³ = 27. 125 − 27 = 98."],
    "TSR5_04": ["Le cube 5×5×5 peint est découpé en 125 petits cubes. Combien de faces d’unités peintes tous les cubes ont-ils au total ?", "Chacune des 6 faces du grand cube est une grille 5×5.", ["150", "125", "144", "162"], "6 × 25 = 150."],
    "TSR5_05": ["Un cube peint 6×6×6 est découpé en 216 petits cubes. Combien ont exactement 2 faces peintes ?", "12(n − 2) avec n = 6.", ["48", "36", "60", "24"], "12 × 4 = 48."],
    "TSR5_06": ["Le cube peint 6×6×6 est découpé en 216 petits cubes. Combien ont exactement 1 visage peint ?", "6(n − 2)² avec n = 6.", ["96", "72", "108", "84"], "6 × 16 = 96."],
    "TSR5_07": ["Le cube peint 6×6×6 est découpé en 216 petits cubes. Combien n’ont aucune face peinte ?", "Bloc intérieur : (n − 2)³.", ["64", "48", "36", "27"], "(6 − 2)³ = 64."],
    "TSR5_08": ["Le cube peint 6×6×6 est découpé en 216 petits cubes. Combien ont exactement 3 faces peintes ?", "Les coins sont toujours au nombre de 8, quelle que soit leur taille.", ["8", "12", "6", "24"], "8 cubes avec 3 faces peintes. (Vérifiez : 8+48+96+64=216 ✓)"],
    "TSR5_09": ["Le cube peint 6×6×6 est découpé en 216 petits cubes. Combien de faces d’unités peintes ont-ils au total ?", "Chaque face du grand cube est une grille 6×6.", ["216", "200", "192", "240"], "6 × 36 = 216."],
    "TSR5_10": ["Dans un cube peint 10×10×10 découpé en 1000 cubes, combien y a-t-il exactement de 2 faces peintes ?", "12(n − 2) pour les cubes sur les bords.", ["96", "120", "80", "108"], "12 × 8 = 96."],
    "TSR5_11": ["Dans le même cube 10×10×10, combien de petits cubes ont exactement 1 face peinte ?", "6(n − 2)² pour les centres des faces.", ["384", "360", "400", "480"], "6 × 64 = 384."],
    "TSR5_12": ["Combien de petits cubes n’ont aucune face peinte ?", "L'intérieur est un cube de côté (n − 2).", ["512", "480", "500", "343"], "(10 − 2)³ = 512."],
    "TSR5_13": ["Laquelle de ces formes PEUT être la section d’un cube ?", "Un plan peut couper au maximum 6 faces. Pouvez-vous passer par le moyen de 6 bords ?", ["Hexagone régulier", "Pentagone régulier", "Octogone régulier", "Ellipses"], "Au moyen de 6 arêtes, vous obtenez un hexagone régulier. La symétrie du cube ne donne pas de pentagones, d'octogones (max. 6 côtés) ou de courbes."],
    "TSR5_14": ["Quel est le nombre maximum de côtés d’une section plane d’un cube ?", "Le polygone de section gagne un côté pour chaque face qui se croise.", ["6", "4", "8", "12"], "Le cube a 6 faces – au plus un hexagone (6 côtés)."],
    "TSR5_15": ["Le dodécaèdre régulier possède 12 faces pentagonales. Chaque face possède 5 arêtes, mais chaque arête est commune à 2 faces. Combien de bords a-t-il ?", "12 × 5 places de bord, chaque bord comptait deux fois.", ["30", "24", "36", "60"], "12 × 5 / 2 = 30 arêtes."],
    "TSR5_16": ["Dans un cube peint 7×7×7, découpé en 343 cubes, combien y a-t-il exactement de 2 faces peintes ?", "12(n − 2) avec n = 7.", ["60", "48", "72", "36"], "12 × 5 = 60."],
    "TSR5_17": ["Dans le cube 7×7×7, combien de petits cubes n’ont pas de face peinte ?", "(n − 2)³.", ["125", "64", "100", "27"], "5³ = 125."],
    "TSR5_18": ["Pour le cube peint n×n×n, le nombre de cubes avec exactement 1 face peinte est 6(n − 2)². Pourquoi y a-t-il 96 dans l’équation ?", "6(n − 2)² = 96 → (n − 2)² = 16.", ["6", "5", "7", "8"], "n − 2 = 4 → n = 6."],
    "TSR5_19": ["Quel est le nombre maximum de côtés d’une section traversant un prisme triangulaire ?", "Le prisme triangulaire possède 5 faces (2 triangles + 3 rectangles). Un plan peut-il supprimer les cinq ?", ["5", "4", "3", "6"], "Un plan incliné peut couper les deux bases et les 3 faces latérales — section pentagonale, maximum 5."],
    "TSR5_20": ["Dans le cube peint 7×7×7, combien de faces unitaires peintes les 343 cubes ont-ils au total ?", "Chacune des 6 faces du grand cube est une grille 7×7.", ["294", "252", "300", "343"], "6 × 49 = 294."],
    "TMP1_1": ["Un fermier are 12 oi. Toți, în afară de cinci, mor. Câte oi au mai rămas?", "Concentrați-vă pe „toate în afară de 5”.", ["5", "7", "12", "0"], "„Toți în afară de 5 mor” înseamnă că 5 supraviețuiesc. Răspunsul este 5 și nu 12 minus 5."],
    "TMP1_2": ["Într-o cursă, depășești persoana de pe locul 3. Unde te afli acum?", "Ce se întâmplă când treci pe lângă cineva: îi iei locul?", ["Le 3ème", "Le 2ème", "Le 4ème", "Le 1er"], "Când treci de persoana de pe locul 3, îi iei locul – devii al 3-lea, nu al 2-lea."],
    "TMP1_3": ["Câte zile de naștere sărbătorește o persoană în medie?", "Te naști o singură dată.", ["1", "Environ 75", "365", "Cela dépend de l'âge"], "Toată lumea are o singură zi de naștere: ziua în care se naște. Restul sunt zile de naștere ale acestei zile."],
    "TMP1_4": ["Dacă ai 5 portocale și iei 2, câte ai?", "Cine a luat portocalele?", ["2", "3", "5", "0"], "Ai luat 2, deci ai 2 la tine. Întrebarea e câte ai tu după ce le-ai luat, nu câte au mai rămas în coș."],
    "TMP1_5": ["A este tatăl lui B, dar B nu este fiul lui A. Cum este posibil acest lucru?", "Toate variantele de gen pentru B.", ["B est la fille de A", "A n'est pas vraiment le père de B", "B est adopté", "Ce sont des beaux-parents"], "B este fată – este fiica lui A. Nu toți copiii sunt băieți."],
    "TMP1_6": ["De câte ori puteți scădea 10 din 100?", "După prima picătură, au mai rămas 100?", ["1", "10", "9", "De l'infini"], "O singură dată – după aceea aveți 90 și scădeți 10 din 90, nu 100."],
    "TMP1_7": ["Dacă un cocoș depune un ou pe acoperiș, în ce direcție se rostogolește oul?", "Ce este mai exact un cocoș?", ["Les coqs ne pondent pas d'œufs", "À gauche", "À droite", "Il reste en haut"], "Cocoșul este mascul și nu depune ouă. Premisa este imposibilă."],
    "TMP1_8": ["Ce cântărește mai mult: un kilogram de pene sau un kilogram de cărămizi?", "Uitați-vă cu atenție la unitatea de măsură.", ["De même", "Les briques", "Plumes", "Ça dépend"], "O livră este o livră, indiferent de material. Ambele cântăresc exact o jumătate de kilogram."],
    "TMP1_9": ["Un tricou costă 50 $ și este cu 50% mai ieftin. Cât plătești?", "Calculează 50% din prețul inițial.", ["25 $", "50 $", "30 $", "15 $"], "50% din 50$ = 25$."],
    "TMP1_10": ["Te afli într-o cameră întunecată, cu o lumânare, o lampă cu ulei și un șemineu. Ai un singur chibrit. Ce pornești prima dată?", "Trebuie să porniți ceva înainte de orice altceva.", ["Le match", "La bougie", "La lampe", "La cheminée"], "Mai întâi trebuie să aprinzi chibritul pentru a putea aprinde restul."],
    "TMP1_11": ["Un avion s-a prăbușit la granița a două țări. Unde să îngropăm supraviețuitorii?", "Citiți cu atenție: pe cine îngropăm?", ["N'enterrez pas les survivants", "Dans le pays de départ", "Dans le pays de destination", "A la frontière"], "Supraviețuitorii sunt în viață: nu-i îngropați."],
    "TMP1_12": ["Câte animale din fiecare specie a luat Moise în arcă?", "Verificați numele din întrebare.", ["Aucun : c'était Noé, pas Moïse", "2", "7", "1"], "Moise nu avea o arcă, dar Noe avea. Întrebarea folosește un nume greșit pentru a vă induce în eroare."],
    "TMP1_13": ["Există 10 păsări pe un gard. Trage unul. Câte au mai rămas pe gard?", "Cum reacționează ceilalți la împușcături?", ["0", "9", "10", "1"], "Zgomotul îi sperie pe toți. Nu a mai rămas nimic."],
    "TMP1_14": ["Un fermier deține 20 de vaci. Toți în afară de 12 mor. Câte au mai rămas?", "\"Toți în afară de 12\".", ["12", "8", "20", "0"], "Doisprezece supraviețuiesc."],
    "TMP1_15": ["Ce urcă întotdeauna și nu coboară niciodată?", "Ceva care crește doar în timp.", ["Votre âge", "Un ballon", "Le soleil", "La température"], "Vârsta este doar în creștere."],
    "TMP1_16": ["O fată lovește mingea la 3 m. Se întoarce la ea fără perete, fără o altă persoană, fără o rotire. Cum?", "Cum a lovit-o?", ["Il l'a frappée verticalement vers le haut", "Le vent", "Il a sauté de l'arbre", "La pente"], "L-a lovit cu piciorul; gravitația l-a adus înapoi."],
    "TMP1_17": ["Ce are cap și coadă, dar nu are corp?", "Obiecte obișnuite, nu animale.", ["Une pièce de monnaie", "Un serpent", "Une aiguille", "Une comète"], "Partea are o față (cap) și o coadă (coadă), fără corp."],
    "TMP1_18": ["Medicul îți dă 5 comprimate: una la fiecare oră. Cât durează tratamentul?", "Când iei prima pastilă?", ["4 heures", "5 heures", "6 heures", "3 heures"], "Ora 0, 1, 2, 3, 4 — ultimele 4 ore între orele unu și cinci. Total 4 ore de la pornire."],
    "TMP1_19": ["Ai un bol cu 6 ouă și scoți 2. Câte ai?", "Unde sunt ouăle după ce le-ai luat?", ["2", "4", "6", "0"], "Ai luat 2 ouă, deci ai 2 la tine. În bol mai sunt 4, dar întrebarea e câte ai tu."],
    "TMP1_20": ["Un băiat are 4 ani, sora lui are jumătate din vârsta lui. Când băiatul are 100 de ani, ce vârstă are sora?", "Diferența de vârstă rămâne aceeași.", ["98", "50", "100", "96"], "Sora este cu 2 ani mai mică (4÷2=2). 100 − 2 = 98."],
    "TMP2_1": ["Un stilou și un notebook costă împreună 1,10 USD. Notebook-ul costă cu 1,00 USD mai mult decât stiloul. Cât costă stiloul injector (pen-ul)?", "Fie x prețul stiloului; notebook-ul costă x + 1,00 $.", ["0,05 $", "0,10 $", "1,00 $", "0,50 $"], "x + (x + 1) = 1,10 → 2x = 0,10 → x = 0,05 USD."],
    "TMP2_2": ["Medicul vă dă 3 comprimate: una la fiecare 45 de minute. Cât durează?", "Când iei prima pastilă?", ["90 minutes", "135 minutes", "45 minutes", "120 minutes"], "La 0, 45 și 90 de minute, se scurge un total de 90 de minute."],
    "TMP2_3": ["5 muncitori construiesc 5 ziduri în 5 zile. Cât durează construirea a 10 ziduri de către 10 muncitori?", "Cât durează ca un lucrător să construiască un zid?", ["5 jours", "10 jours", "2,5 jours", "1 jour"], "Fiecare construiește 1 zid în 5 zile. 10 persoane, 10 pereți paraleli — tot 5 zile."],
    "TMP2_4": ["Două monede sunt 30 de cenți. Unul nu este nichel (5 ¢). Care sunt monedele?", "„Una nu este o monedă de cinci cenți” — care este cealaltă?", ["25 ¢ et 5 ¢ (quart + nickel)", "Deux pièces de 10 ¢", "50 ¢", "10 ¢ et 5 ¢"], "Unul este un sfert (25 ¢), nu nichel; celălalt este nichel (5 ¢). Total 30 ¢."],
    "TMP2_5": ["Înmulțiți toate cifrele unei tastaturi telefonice (de la 0 la 9). Care este produsul?", "Ce se întâmplă când înmulțiți cu un anumit număr?", ["0", "3 628 800", "362 880", "45"], "Printre numere se numără 0. Orice produs care include 0 este 0."],
    "TMP2_6": ["O familie are 4 băieți și 3 fete. Fiecare băiat are la fel de multe surori ca și frați. Fiecare fată are de două ori mai mulți frați decât surori. Câți copii sunt?", "Numărați din perspectiva fiecărui copil.", ["7", "8", "6", "10"], "Băiat: 3 frați, 3 surori✓. Fiică: 4 frați, 2 surori (4 = 2×2)✓. Total 7."],
    "TMP2_7": ["Un tren electric se îndreaptă spre nord. Vântul bate dinspre vest. Unde se duce fumul?", "Ce tip de propulsie are trenul?", ["Il n'y a pas de fumée", "Ouest", "Nord", "Est"], "Trenul electric nu arde combustibil, nu produce fum."],
    "TMP2_8": ["8 persoane construiesc un zid în 10 ore. Cât durează pentru 4 persoane?", "Jumătate dintre oameni își dublează timpul.", ["20 heures", "5 heures", "40 heures", "10 heures"], "10 × 2 = 20 ore."],
    "TMP2_9": ["Câte luni ale anului au (cel puțin) 30 de zile?", "Unele luni au mai mult de 30 de zile.", ["11", "4", "6", "7"], "Fiecare lună are cel puțin 30 de zile, cu excepția lunii februarie. Deci 11 luni."],
    "TMP2_10": ["Săpați 6 găuri: 3 mari și 3 mici. Câte găuri aveți", "Dimensiunea schimbă faptul că este o gaură?", ["6", "3", "9", "0"], "Cele 6 găuri."],
    "TMP2_11": ["Poți numi trei zile consecutive fără luni, marți, miercuri, joi, vineri, sâmbătă, duminică?", "Termeni relativi, nu nume proprii.", ["Hier, aujourd'hui et demain", "Jour 1, 2, 3", "Impossible", "Matin, midi, soir"], "Ieri, azi, mâine sunt întotdeauna trei zile consecutive."],
    "TMP2_12": ["Cât înseamnă 1/2 din 2/3 din 3/4 din 4/5 din 100?", "Simplificați fracțiile înainte de înmulțire.", ["20", "10", "50", "25"], "1/2 × 2/3 × 3/4 × 4/5 = 1/5. 1/5 × 100 = 20."],
    "TMP2_13": ["Un nufăr își dublează suprafața în fiecare zi. În ziua 20, umpleți lacul. Ce zi a acoperit exact 25%?", "Faceți un pas înapoi: împărțiți la 2 în fiecare zi.", ["Jour 18", "Jour 5", "Jour 15", "Jour 10"], "Ziua 20 : 100%. Ziua 19 : 50%. Ziua 18 : 25%."],
    "TMP2_14": ["O cărămidă cântărește 1 kg plus jumătate din greutatea sa. Cât cântărește?", "Fie b greutatea: b = 1 + b/2.", ["2kg", "1,5kg", "3kg", "1 kg"], "b/2 = 1 → b = 2 kg."],
    "TMP2_15": ["6 bărbați sapă 6 găuri în 6 ore. Cât durează să sape 3 gropi pentru 3 persoane?", "Cât timp durează ca o persoană să sape o groapă?", ["6 heures", "3 heures", "12 heures", "9 heures"], "Fiecare sapă 1 gaură în 6 ore. 3 persoane, 3 găuri în paralel — tot 6 ore."],
    "TMP2_16": ["Care este următoarea literă: O, T, T, F, F, S, S,?", "În limba engleză: inițialele numerelor Unu, Doi, Trei...", ["E", "N", "T", "H"], "Unu, doi, trei, patru, cinci, șase, șapte, opt → O, T, T, F, F, S, S, E."],
    "TMP2_17": ["Ai 8 mingi: 7 identice, una mai grea. Cu o scală, câte greutăți minime sunt necesare pentru a o găsi?", "Împărțiți-vă în trei grupuri, nu în două.", ["2", "3", "1", "4"], "3 la 3; apoi 1 la 1 sau grupul dur. Maxim 2 cântăriri."],
    "TMP2_18": ["Într-o cursă, treci pe lângă ultima. Pe ce loc te afli?", "Cine se află în spatele ultimului?", ["C'est impossible", "Le dernier", "L'avant-dernier", "Le premier"], "Nu este nimeni în spatele ultimului, nu poți fi în spatele lui ca să-l bați."],
    "TMP2_19": ["3 pisici prind 3 șoareci în 3 minute. Cât durează ca 100 de pisici să prindă 100 de șoareci?", "Câte minute prinde o pisică un șoarece?", ["3 minutes", "100 minutes", "33 minutes", "1 minute"], "Fiecare prinde 1 șoarece în 3 minute. În paralel — tot 3 minute."],
    "TMP2_20": ["Ce fracțiune de zi înseamnă 6 ore?", "Câte ore sunt într-o zi?", ["1/4", "1/6", "1/3", "1/2"], "6/24 = 1/4."],
    "TMP3_1": ["6 mașini fac 6 jucării în 6 minute. Cât timp durează 12 mașini pentru a face 12 jucării?", "Câte minute face o mașină o jucărie?", ["6 minutes", "12 minutes", "3 minutes", "1 minute"], "Fiecare face o jucărie în 6 minute. 12 mașini în paralel — de asemenea, 6 minute."],
    "TMP3_2": ["Ceasul arată ora 06:00. Care este unghiul dintre indicatorul orar și indicatorul minutar?", "Unde indică limbile la ora 6 fix?", ["180°", "90°", "120°", "360°"], "Minute hand la ora 12, hour hand la ora 6 — linie dreaptă, 180°."],
    "TMP3_3": ["Ceasul arată ora 9:00. Care este unghiul dintre limbi?", "Unde se uită limbile la ora 9 fix?", ["90°", "180°", "270°", "45°"], "Minute hand la ora 12, hour hand la ora 9 – unghi drept, 90°."],
    "TMP3_4": ["Într-o grilă, coloana 1 + coloana 2 = coloana 3. Linii: [3, 5, 8], [7, 2, 9], [4, 6,?]. Găsește numărul lipsă.", "Aplicați aceeași regulă la al treilea rând.", ["10", "8", "12", "6"], "4 + 6 = 10."],
    "TMP3_5": ["Într-o grilă, coloana 1 × coloana 2 = coloana 3. Linii: [2, 5, 10], [3, 4, 12], [6, 3,?]. Găsește numărul lipsă.", "Înmulțiți primele două coloane din al treilea rând.", ["18", "9", "15", "21"], "6 × 3 = 18."],
    "TMP3_6": ["Un melc urcă 4 m ziua și alunecă 2 m noaptea. Zidul are 12 m. În câte zile ajunge în vârf?", "În ultima zi poate atinge vârful înainte să mai alunece înapoi noaptea.", ["5 zile", "6 zile", "4 zile", "10 zile"], "Progres net +2 m pe ciclu zi–noapte. După 4 zile: 8 m. În ziua a 5-a urcă 8+4=12 m și ajunge în vârf înainte de noapte."],
    "TMP3_7": ["2 persoane vopsesc 2 camere în 2 ore. Cât durează cu 4 persoane și 4 dormitoare?", "Câte ore pictează un om o cameră?", ["2 heures", "4 heures", "1 heure", "8 heures"], "Fiecare vopsește 1 bucată în 2 ore. 4 persoane, 4 bucăți în paralel — 2 ore de asemenea."],
    "TMP3_8": ["Cumperi ceva cu 3 $ și îl vinzi cu 5 $. Apoi cumperi altceva cu 6 $ și îl vinzi cu 9 $. Care este beneficiul total?", "Profitul fiecărei tranzacții în parte.", ["5 $", "3 $", "2 $", "6 $"], "5−3=2, 9−6=3. Total $ 5."],
    "TMP3_9": ["O broască sare 3 m înainte și alunecă 1 m înapoi pe ciclu. Câte sărituri trebuie să depășească 10 m?", "Ultimul salt se poate face fără recidivă.", ["5 sauts", "4 sauts", "6 sauts", "10 sauts"], "După 4 cicluri: 8 m. Al cincilea salt: 8+3=11 m > 10. Deci 5."],
    "TMP3_10": ["Tom are de 3 ori vârsta lui Jim. Peste 10 ani, Tom va avea de două ori vârsta lui Jim. Câți ani are Jim acum?", "T = 3J; T+10 = 2(D+10).", ["10", "5", "15", "20"], "3D+10 = 2D+20 → D = 10."],
    "TMP3_11": ["Cumpărați un cal cu 60 $, îl vindeți cu 70 $, îl cumpărați cu 80 $ și îl revindeți cu 90 $. Profit total?", "Fiecare tranzacție separat.", ["20 $", "10 $", "30 $", "0 $"], "+10$ apoi +10$ = 20$."],
    "TMP3_12": ["Împăturești o foaie în jumătate de 7 ori. Câte straturi?", "Fiecare pliu dublează straturile.", ["128", "64", "14", "256"], "2ա = 128."],
    "TMP3_13": ["Un număr prim înmulțit cu el însuși dă 169. Care este acest număr?", "Rădăcina pătrată a lui 169.", ["13", "11", "17", "7"], "√169 = 13, care este prim."],
    "TMP3_14": ["Două trenuri sunt la 100 de mile distanță, fiecare îndreptându-se cu 50 mph unul spre celălalt. O muscă zboară cu 75 mph între ele. Cât durează ca trenurile să se traverseze reciproc?", "Cât de curând se vor întâlni?", ["75 milles", "100 milles", "50 milles", "150 milles"], "Viteză relativă 100 mph → 1 oră. Zbor: 75 × 1 = 75 mile."],
    "TMP3_15": ["Care este cel mai mic număr divizibil cu 1, 2, 3, 4, 5 și 6?", "Cel mai mic multiplu comun (CMMMC).", ["60", "30", "120", "720"], "CMMMC(1…6) = 60."],
    "TMP3_16": ["Numărând de la 1 la 100, de câte ori apare numărul 7?", "Unitățile și zecile separat.", ["20", "10", "11", "19"], "Unități: 7.17,…,97 — 10. Duzină: 70–79 — 10. Total 20."],
    "TMP3_17": ["Un număr crește cu 20% și devine 60. Ce a fost inițial?", "1,2x = 60.", ["50", "48", "72", "40"], "x = 60 / 1,2 = 50."],
    "TMP3_18": ["Împăturești o foaie în jumătate de 10 ori. Câte straturi?", "Fiecare îndoire se dublează.", ["1024", "100", "512", "2048"], "2¹⁰ = 1024."],
    "TMP3_19": ["Produsul a două numere întregi pozitive consecutive este 156. Ce este?", "Două numere consecutive al căror produs este 156.", ["12 et 13", "11 et 12", "13 et 14", "10 et 15"], "12 × 13 = 156."],
    "TMP3_20": ["3×3 Magic Square: Fiecare rând, coloană și diagonală însumează 15. Primul rând [2, 7, 6], mijlocul [9, 5, 1]. Care este prima cifră a ultimei linii?", "Prima coloană totalizează 15.", ["4", "3", "6", "8"], "2 + 9 +? = 15→? = 4."],
    "TMP4_1": ["O colonie de bacterii se dublează la fiecare oră și umple complet o oală la prânz. La ce oră era oala la un sfert?", "Înapoi: înjumătățește la fiecare oră.", ["10h00", "11h00", "9h00", "6h00"], "Prânz: 100%. 11:00 : 50%. 10:00 : 25%."],
    "TMP4_2": ["Vous disposez de 24 pièces ; l'une est fausse et plus légère. Combien de pesées minimum sur une balance pour la retrouver avec certitude ?", "Divisez-vous en trois groupes à chaque étape.", ["3", "4", "5", "2"], "8 contre 8, puis dans le groupe léger 3 contre 3, puis 1 contre 1 — 3 pesées."],
    "TMP4_3": ["Une corde est coupée en 3 morceaux. Chaque morceau est coupé en 3 plus petits. Combien de pièces au total ?", "3 × 3.", ["9", "6", "12", "27"], "3 × 3 = 9."],
    "TMP4_4": ["Un ver se trouve au fond d'un puits de 30 m. Il grimpe de 5 m le jour et glisse de 4 m la nuit. Combien de jours sort-il?", "Le dernier jour, il ressort sans reculer.", ["26 jours", "30 jours", "25 jours", "27 jours"], "Net +1 m/jour. Après 25 jours : 25 m. Jour 26 : 25+5=30 m."],
    "TMP4_5": ["8 hommes construisent un mur en 10 jours. Combien de jours avec 5 hommes ?", "Travail total = personnes × jours.", ["16 jours", "12 jours", "20 jours", "8 jours"], "8×10 = 80 jours-homme. 80/5 = 16 jours."],
    "TMP4_6": ["Les tuyaux A et B remplissent un réservoir en 6 h et 3 h respectivement. Combien de temps restent-ils tous les deux ouverts ?", "Ajoute les débits : 1/6 + 1/3 par heure.", ["2 heures", "4,5 heures", "3 heures", "1,5 heures"], "1/6+2/6=1/2 par heure → 2 heures."],
    "TMP4_7": ["Un rectangle est 3 fois plus long que large. Le périmètre est de 48 m. Quelle est la superficie ?", "l = 3w; 2(s+3s)=48.", ["108 m²", "96 m²", "144 m²", "48 m²"], "8w=48 → w=6, longueur 18 m, aire 108 m²."],
    "TMP4_8": ["Un nombre augmente de 20 %, puis diminue de 20 %. Quel est le changement net par rapport à l'original ?", "Appliquez les pourcentages un à la fois.", ["4% de diminution", "0%", "Augmentation de 4 %", "2% de réduction"], "100 → 120 → 96. -4% net."],
    "TMP4_9": ["Le magasin augmente les prix de 25 %, puis réduit de 20 %. Le changement net ?", "1,25 × 0,80.", ["0 % (aucun changement)", "+5%", "-5%", "+45%"], "1,25 × 0,80 = 1 — en place."],
    "TMP4_10": ["Suma primelor 20 de numere naturale pozitive?", "n(n+1)/2.", ["210", "200", "190", "220"], "20×21/2 = 210."],
    "TMP4_11": ["Unghiul dintre ceas arată ora 4:30?", "Programul este între patru și cinci și jumătate.", ["45°", "90°", "60°", "30°"], "Minut 180°, oră 135°, diferență 45°."],
    "TMP4_12": ["Mașina parcurge 60 km cu 30 km/h, apoi 60 km cu 60 km/h. Viteza medie?", "Distanța totală / timpul total.", ["40km/h", "45km/h", "50km/h", "35km/h"], "2h + 1h = 3h; 120/3 = 40 km/h."],
    "TMP4_13": ["Dacă 2¹⁰ = 1024, ce este 2¹²?", "2¹⁰ × 2².", ["4096", "2048", "8192", "1248"], "1024 × 4 = 4096."],
    "TMP4_14": ["Un robinet umple piscina în 4 ore; scurgerea o curăță în 8 ore. Cât durează să le umple pe amândouă?", "Debit net = Umplere - Scurgere.", ["8 heures", "6 heures", "12 heures", "4 heures"], "1/4 − 1/8 = 1/8 pe oră → 8 ore."],
    "TMP4_15": ["Prețul scade cu 10%, apoi cu încă 10%. Scăderea totală în comparație cu originalul?", "Al doilea 10% este la prețul deja redus.", ["19%", "20%", "18%", "21%"], "0,9 × 0,9 = 0,81 → scădere de 19%."],
    "TMP4_16": ["Găsire x: 3x + 7 = 22.", "Izolați x.", ["5", "7", "3", "10"], "3x=15 → x=5."],
    "TMP4_17": ["Un train de 100 m roule à 50 m/s. Combien de temps leur faut-il pour dépasser complètement un poteau ?", "La longueur du train doit être couverte.", ["2 secondes", "1 seconde", "4 secondes", "0,5 seconde"], "100/50 = 2 s."],
    "TMP4_18": ["Deux ouvriers terminent un travail en 12 jours. Un en 20 jours. Combien faut-il à l'autre seul ?", "1/12 - 1/20.", ["30 jours", "24 jours", "15 jours", "40 jours"], "1/30 par jour → 30 jours."],
    "TMP4_19": ["Vous investissez 1 000 $ à 5 % d’intérêt simple par an, pendant 3 ans. Quel est le montant total des intérêts ?", "Intérêt simple = capital × taux × temps.", ["150 $", "1 150 $", "50 $", "300 $"], "1 000 × 0,05 × 3 = 150 $."],
    "TMP4_20": ["Le fermier possède des poules et des vaches. 20 têtes et 56 pieds. combien de poulets", "g + v = 20 ; 2g + 4v = 56.", ["12", "8", "14", "10"], "v=8, g=12."],
    "TMP5_1": ["Vous avez deux cordes ; chacun brûle complètement en 1 heure exactement, mais de manière irrégulière. Comment mesure-t-on exactement 45 minutes ?", "Que se passe-t-il si vous allumez une corde aux deux extrémités ?", ["Vous allumez la corde 1 aux deux extrémités et la corde 2 à une extrémité, simultanément", "Vous allumez les deux cordes à une extrémité", "Coupez une corde en quatre et allumez un morceau", "Tu allumes une corde, tu attends qu'elle brûle, puis l'autre"], "La corde 1 (les deux extrémités) brûle en 30 min. Allumez ensuite l’autre extrémité de la corde 2 – encore 15 minutes. Totale : 45 minutes."],
    "TMP5_2": ["Deux pères et deux fils mangent. Mangez exactement 3 œufs, un chacun. Comment est-ce possible ?", "Une personne peut-elle jouer deux rôles ?", ["Grand-père, père et fils (3 personnes)", "On n'a pas mangé", "Il y en avait 4, mais les œufs étaient partagés", "Quelqu'un a mangé deux œufs"], "Trois générations : grand-père (père), père (et fils et père), fils. Deux pères + deux fils = 3 personnes."],
    "TMP5_3": ["100 casiers en enfilade, tous verrouillés. L'élève k change chaque kième casier. Combien restent-ils ouverts à la fin ?", "Une armoire est ouverte si elle est commutée un nombre impair de fois. Quels nombres ont un nombre impair de diviseurs ?", ["10", "50", "25", "0"], "Carrés parfaits uniquement : 1, 4, 9, 16, 25, 36, 49, 64, 81, 100 — 10 armoires."],
    "TMP5_4": ["Trois interrupteurs à l’extérieur d’une pièce fermée contrôlent trois ampoules à l’intérieur. Vous ne pouvez entrer qu’une seule fois. Comment identifier chaque interrupteur ?", "Une ampoule restée allumée longtemps reste chaude même après extinction.", ["Allumez 1, attendez, éteignez ; allumez 2 ; entrez : chaude éteinte = 1, allumée = 2, froide éteinte = 3", "Actionnez-les un par un et entrez après chaque action", "Allumez puis éteignez rapidement les trois, puis entrez", "Regardez par le trou de la serrure après chaque changement"], "Méthode correcte : 1 allumé quelques minutes, puis éteint ; 2 allumé ; 3 éteint. En entrant : chaude éteinte = 1, allumée = 2, froide éteinte = 3."],
    "TMP5_5": ["Trois cartons étiquetés « Pommes », « Oranges », « Mélange ». Toutes les étiquettes sont fausses. Vous prélevez un fruit d’une boîte. Laquelle ouvrir ?", "La boîte « Mélange » n’est pas un mélange si l’étiquette est fausse.", ["Boîte « Mélange »", "Boîte « Pommes »", "Boîte « Oranges »", "N’importe quelle boîte"], "Ouvrez « Mélange » : le contenu est homogène (pommes ou oranges). Selon le fruit tiré, on en déduit tout le classement réel."],
    "TMP5_6": ["Un homme a trois filles. Le produit des âges est 36. La somme est le numéro de la maison voisine (ambigu). L'aîné joue du piano. Quels sont les âges ?", "Deux triplets de diviseurs de 36 ont la même somme. \"Le plus gros\" élimine un cas.", ["2, 2 et 9", "1, 6 et 6", "3, 3 et 4", "1, 4 et 9"], "Sommes 13 : {1,6,6} et {2,2,9}. Il existe un «plus grand» unique → {2, 2, 9}."],
    "TMP5_7": ["Le problème de Monty Hall : vous choisissez la porte 1 sur 3 (une voiture, deux chèvres). L'hôte ouvre la porte 3 - chèvre. Est-ce que tu te changes à la porte 2 ?", "Quelle était la probabilité initiale pour votre porte ?", ["Oui – le changement gagne 2/3 du temps", "Non, c'est 50/50", "Ce n'est pas grave", "Non, le premier choix est généralement le bon"], "Votre choix : 1/3. La porte restante est 2/3. Le changement double les chances."],
    "TMP5_8": ["Combien de carrés de n’importe quelle taille sur un échiquier 8×8 ?", "Comptez séparément 1×1, 2×2,… 8×8.", ["204", "64", "256", "100"], "8²+7²+…+1² = 204."],
    "TMP5_9": ["La somme des nombres de 1 à 100 ?", "Formule de Gauss : n(n+1)/2.", ["5050", "5000", "10000", "10100"], "100×101/2 = 5050."],
    "TMP5_10": ["Combien de zéros à la fin de 100 !?", "Les zéros proviennent des facteurs 10 = 2×5. Comptez les puissances de 5.", ["24", "20", "25", "10"], "⌊100/5⌋ + ⌊100/25⌋ = 24."],
    "TMP5_11": ["Le paysan traverse la rivière avec le loup, la chèvre et le chou. Bateau : fermier + un objet. Le loup mange la chèvre laissée seule ; la chèvre mange le chou. Par quoi ça commence ?", "Quel couple peut-on laisser seul sur le rivage ?", ["Chèvre", "Le loup", "Chou", "Ce n'est pas grave"], "D'abord la chèvre. Le loup et le chou sont en sécurité. Puis le reste à tour de rôle."],
    "TMP5_12": ["Partant d'un couple de lapins, ils arrivent à maturité en 1 mois et produisent un nouveau couple tous les mois après maturité. Combien de paires après 6 mois ?", "Suite de Fibonacci : 1, 1, 2, 3, 5, 8, …", ["8", "13", "6", "10"], "Mois 1 à 6 : 1, 1, 2, 3, 5, 8 paires."],
    "TMP5_13": ["Nombre minimum de coups dans les Tours de Hanoï avec 5 disques ?", "2ⁿ − 1, n = nombre de disques.", ["31", "32", "63", "15"], "2⁵ − 1 = 31."],
    "TMP5_14": ["Nombre minimum de personnes dans une pièce tel qu'il y a > 50 % de probabilité que deux aient le même anniversaire ?", "Le paradoxe de l’anniversaire : la réponse est loin d’être ce que l’on voit.", ["23", "50", "183", "365"], "Chez 23 personnes, la probabilité dépasse 50 %."],
    "TMP5_15": ["Dans une pièce de 23 personnes, quelle est la probabilité approximative qu’au moins deux aient le même anniversaire ?", "Le résultat du paradoxe de l'anniversaire.", ["environ 50%", "environ 6%", "environ 25%", "environ 75%"], "Avec 23 personnes, ~50,7%."],
    "TMP5_16": ["Sur une île, les chevaliers disent la vérité, les escrocs mentent. Dire : \"Nous sommes tous les deux des escrocs\". Qu’est-ce que A ?", "Si A était un chevalier, cette affirmation pourrait-elle être vraie ?", ["Escroc", "Chevalier", "On ne peut pas déterminer", "Aucun"], "Un chevalier ne pouvait pas dire « les deux escrocs ». Donc A ment ; l'affirmation est fausse : ils ne sont pas tous les deux des escrocs, l'autre est un chevalier."],
    "TMP5_17": ["La somme des angles intérieurs d'un heptagone (7 côtés) ?", "(n − 2) × 180°.", ["900°", "720°", "1080°", "1260°"], "5 × 180° = 900°."],
    "TMP5_18": ["Combien de carrés de n’importe quelle taille dans une grille 4×4 ?", "1×1, 2×2, 3×3, 4×4.", ["30", "16", "20", "25"], "4²+3²+2²+1² = 30."],
    "TMP5_19": ["Vous lancez une pièce équitable 3 fois. La probabilité d'apparaître au moins une fois « tête » ?", "Le complément : jamais tête (trois fois page).", ["7/8", "3/4", "1/2", "1/8"], "P(pas de tête) = (1/2)³ = 1/8. P(au moins une tête) = 7/8."],
    "TMP5_20": ["Combien de rectangles dans les lignes d'une grille 3×3 (4 horizontales, 4 verticales) ?", "Vous en choisissez 2 horizontaux et 2 verticaux.", ["36", "18", "24", "9"], "C(4,2)² = 36."],
  }
});
